                                        <button onclick="document.getElementById('cfg-custom-bg-file').click()" class="dash-btn" style="padding:0 12px; font-size:11px; white-space:nowrap; background:#21262d; border:1px solid #30363d; color:#c9d1d9; border-radius:4px; cursor:pointer;">Examinar</button>
