        // =========================================================================
        // BÚSQUEDA Y REEMPLAZO GLOBAL RECURSIVO
        // =========================================================================
        function searchWorkspace(query) {
            const resultsContainer = document.getElementById('search-results-container');
            resultsContainer.innerHTML = '<div style="color:#8b949e;padding:8px;text-align:center;">Buscando...</div>';
            
            if (!query) {
                resultsContainer.innerHTML = '<div style="color:#8b949e;padding:8px;text-align:center;">Escribe algo para buscar.</div>';
                return;
            }
            
            const results = [];
            const maxResults = 150;
            
            function searchDir(dirPath) {
                if (results.length >= maxResults) return;
                try {
                    const files = fs.readdirSync(dirPath);
                    for (const file of files) {
                        if (results.length >= maxResults) break;
                        const fullPath = path.join(dirPath, file);
                        const stat = fs.statSync(fullPath);
                        
                        if (stat.isDirectory()) {
                            if (file === 'node_modules' || file === '.git' || file === '.venv' || file === '__pycache__' || file === 'uploads') {
                                continue;
                            }
                            searchDir(fullPath);
                        } else {
                            const ext = path.extname(file).toLowerCase();
                            if (['.exe', '.png', '.zip', '.gif', '.jpg', '.jpeg', '.pdf', '.mp3', '.mp4', '.sqlite', '.tar', '.gz'].includes(ext)) {
                                continue;
                            }
                            if (stat.size > 2 * 1024 * 1024) { // Ignorar archivos mayores a 2MB
                                continue;
                            }
                            
                            const content = fs.readFileSync(fullPath, 'utf8');
                            const lines = content.split('\n');
                            lines.forEach((line, idx) => {
                                if (results.length >= maxResults) return;
                                if (line.toLowerCase().includes(query.toLowerCase())) {
                                    results.push({
                                        filePath: fullPath,
                                        relPath: path.relative(workspaceRoot, fullPath),
                                        lineNum: idx + 1,
                                        content: line.trim()
                                    });
                                }
                            });
                        }
                    }
                } catch(e) {
                    console.error("Error al buscar en: " + dirPath, e);
                }
            }
            
            searchDir(workspaceRoot);
            
            resultsContainer.innerHTML = '';
            if (results.length === 0) {
                resultsContainer.innerHTML = '<div style="color:#8b949e;padding:8px;text-align:center;">No se encontraron coincidencias.</div>';
                return;
            }
            
            // Agrupar resultados por archivo
            const filesMap = {};
            results.forEach(res => {
                if (!filesMap[res.relPath]) filesMap[res.relPath] = [];
                filesMap[res.relPath].push(res);
            });
            
            Object.keys(filesMap).forEach(relPath => {
                const groupDiv = document.createElement('div');
                groupDiv.style.marginBottom = '8px';
                
                const fileHeader = document.createElement('div');
                fileHeader.style.cssText = `font-weight:bold;color:#e6edf3;padding:4px 6px;cursor:pointer;background:#161b22;border:1px solid #30363d;border-radius:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin-bottom:2px;font-size:11px;`;
                fileHeader.textContent = relPath;
                groupDiv.appendChild(fileHeader);
                
                filesMap[relPath].forEach(res => {
                    const item = document.createElement('div');
                    item.className = 'search-result-item';
                    item.style.cssText = `padding:4px 8px;cursor:pointer;font-family:monospace;font-size:11px;display:flex;gap:8px;color:#8b949e;border-radius:3px;margin-bottom:1px;`;
                    
                    const lineSpan = document.createElement('span');
                    lineSpan.style.color = '#7c3aed';
                    lineSpan.style.fontWeight = 'bold';
                    lineSpan.textContent = res.lineNum;
                    
                    const textSpan = document.createElement('span');
                    textSpan.style.cssText = `flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;`;
                    textSpan.textContent = res.content;
                    
                    item.appendChild(lineSpan);
                    item.appendChild(textSpan);
                    
                    item.addEventListener('click', () => {
                        openFileAndGoToLine(res.filePath, res.lineNum);
                    });
                    
                    groupDiv.appendChild(item);
                });
                
                resultsContainer.appendChild(groupDiv);
            });
        }

        function replaceWorkspace(query, replacement) {
            if (!query) {
                showToast("Introduce un término de búsqueda", "warning");
                return;
            }
            if (replacement === undefined) {
                showToast("Introduce el texto de reemplazo", "warning");
                return;
            }
            
            let filesModified = 0;
            let replacementsCount = 0;
            
            function replaceInDir(dirPath) {
                try {
                    const files = fs.readdirSync(dirPath);
                    for (const file of files) {
                        const fullPath = path.join(dirPath, file);
                        const stat = fs.statSync(fullPath);
                        
                        if (stat.isDirectory()) {
                            if (file === 'node_modules' || file === '.git' || file === '.venv' || file === '__pycache__' || file === 'uploads') {
                                continue;
                            }
                            replaceInDir(fullPath);
                        } else {
                            const ext = path.extname(file).toLowerCase();
                            if (['.exe', '.png', '.zip', '.gif', '.jpg', '.jpeg', '.pdf', '.mp3', '.mp4', '.sqlite'].includes(ext)) {
                                continue;
                            }
                            if (stat.size > 2 * 1024 * 1024) {
                                continue;
                            }
                            
                            const content = fs.readFileSync(fullPath, 'utf8');
                            // Reemplazo global (case-insensitive)
                            const regex = new RegExp(query.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&'), 'gi');
                            
                            if (regex.test(content)) {
                                const matches = content.match(regex);
                                replacementsCount += matches.length;
                                
                                const newContent = content.replace(regex, replacement);
                                fs.writeFileSync(fullPath, newContent, 'utf8');
                                filesModified++;
                                
                                // Si está abierto en Monaco, actualizar modelo en vivo
                                if (isMonacoLoaded && fileModels[fullPath]) {
                                    fileModels[fullPath].setValue(newContent);
                                }
                            }
                        }
                    }
                } catch(e) {
                    console.error("Error al reemplazar en: " + dirPath, e);
                }
            }
            
            replaceInDir(workspaceRoot);
            
            if (filesModified > 0) {
                showToast(`Reemplazado: ${replacementsCount} ocurrencias en ${filesModified} archivos.`, "success");
                searchWorkspace(query);
                renderExplorer();
            } else {
                showToast("No se encontraron coincidencias para reemplazar.", "warning");
            }
        }

        function openFileAndGoToLine(filePath, lineNum) {
            openFileInEditor(filePath);
            setTimeout(() => {
                const editor = (activePane === 1) ? monacoEditor : monacoEditor2;
                if (isMonacoLoaded && editor) {
                    editor.revealLineInCenter(lineNum);
                    editor.setPosition({ lineNumber: lineNum, column: 1 });
                    editor.focus();
                } else {
                    const ta = document.getElementById('fallback-textarea-' + activePane);
                    if (ta) {
                        ta.focus();
                    }
                }
            }, 150);
        }

