        function toggleExtension(id) {
            if (id === 'dracula') {
                const settings = getSavedSettings();
                if (settings.theme !== 'dracula') {
                    settings.theme = 'dracula';
                    saveSettings(settings);
                    showToast("Dracula Theme activado con éxito", "success");
                } else {
                    settings.theme = 'classic';
                    saveSettings(settings);
                    showToast("Dracula Theme desactivado", "info");
                }
            } else if (id === 'onedark') {
                const settings = getSavedSettings();
                if (settings.theme !== 'one-dark') {
                    settings.theme = 'one-dark';
                    saveSettings(settings);
                    showToast("One Dark Theme activado con éxito", "success");
                } else {
                    settings.theme = 'classic';
                    saveSettings(settings);
                    showToast("One Dark Theme desactivado", "info");
                }
            } else if (id === 'catppuccin') {
                const settings = getSavedSettings();
                if (settings.theme !== 'catppuccin') {
                    settings.theme = 'catppuccin';
                    saveSettings(settings);
                    showToast("Catppuccin Mocha activado con éxito", "success");
                } else {
                    settings.theme = 'classic';
                    saveSettings(settings);
                    showToast("Catppuccin Mocha desactivado", "info");
                }
            } else if (id === 'nord') {
                const settings = getSavedSettings();
                if (settings.theme !== 'nord') {
                    settings.theme = 'nord';
                    saveSettings(settings);
                    showToast("Nord Theme activado con éxito", "success");
                } else {
                    settings.theme = 'classic';
                    saveSettings(settings);
                    showToast("Nord Theme desactivado", "info");
                }
            } else if (id === 'autosave') {
                const installed = !extensionsState.autosave?.installed;
                extensionsState.autosave.installed = installed;
                saveExtensionsState();
                if (installed) {
                    startAutosave();
                    showToast("Autoguardado activado (5 segundos)", "success");
                } else {
                    stopAutosave();
                    showToast("Autoguardado desactivado", "info");
                }
            } else if (id === 'csslinter') {
                const installed = !extensionsState.csslinter?.installed;
                extensionsState.csslinter.installed = installed;
                saveExtensionsState();
                if (installed) {
                    startCSSLinter();
                    showToast("Linter CSS activado en segundo plano", "success");
                } else {
                    stopCSSLinter();
                    showToast("Linter CSS desactivado", "info");
                }
            } else if (id === 'zenmode') {
                const installed = !extensionsState.zenmode?.installed;
                extensionsState.zenmode.installed = installed;
                saveExtensionsState();
                const zenStatus = document.getElementById('status-zenmode');
                if (installed) {
                    if (zenStatus) zenStatus.style.display = 'inline-flex';
                    showToast("Modo Zen activado (Usa Ctrl+K Z o la barra de estado)", "success");
                } else {
                    if (zenStatus) zenStatus.style.display = 'none';
                    if (document.body.classList.contains('zen-active')) {
                        toggleZenMode();
                    }
                    showToast("Modo Zen desactivado", "info");
                }
            } else if (id === 'formatter') {
                const installed = !extensionsState.formatter?.installed;
                extensionsState.formatter.installed = installed;
                saveExtensionsState();
                if (installed) {
                    registerMonacoFormatter();
                    showToast("Formateador offline activado (Alt+Shift+F)", "success");
                } else {
                    showToast("Formateador offline desactivado", "info");
                }
            } else if (id === 'todotree') {
                const installed = !extensionsState.todotree?.installed;
                extensionsState.todotree.installed = installed;
                saveExtensionsState();
                const todoIcon = document.getElementById('btn-sidebar-todotree');
                if (installed) {
                    if (todoIcon) todoIcon.style.display = 'inline-flex';
                    showToast("Todo Tree activado en panel lateral", "success");
                } else {
                    if (todoIcon) todoIcon.style.display = 'none';
                    const activeIcon = document.querySelector('.sidebar-icon.active');
                    if (activeIcon && activeIcon.dataset.sidebar === 'todotree') {
                        document.querySelector('.sidebar-icon[data-sidebar="explorer"]').click();
                    }
                    showToast("Todo Tree desactivado", "info");
                }
            } else if (id === 'telemetry') {
                const installed = !extensionsState.telemetry?.installed;
                extensionsState.telemetry.installed = installed;
                saveExtensionsState();
                const telIcon = document.getElementById('btn-sidebar-telemetry');
                if (installed) {
                    if (telIcon) telIcon.style.display = 'inline-flex';
                    startTelemetryMonitor();
                    showToast("Puente de Telemetría activado", "success");
                } else {
                    if (telIcon) telIcon.style.display = 'none';
                    stopTelemetryMonitor();
                    const activeIcon = document.querySelector('.sidebar-icon.active');
                    if (activeIcon && activeIcon.dataset.sidebar === 'telemetry') {
                        document.querySelector('.sidebar-icon[data-sidebar="explorer"]').click();
                    }
                    showToast("Puente de Telemetría desactivado", "info");
                }
            }
            updateExtensionsUI();
        }

