        // --- 1. MODO ZEN (CONCENTRACIÓN) ---
        function toggleZenMode() {
            if (!extensionsState.zenmode?.installed) {
                showToast("Debes instalar la extensión 'Modo Zen' primero.", "warning");
                return;
            }
            
            const isZen = document.body.classList.toggle('zen-active');
            
            setTimeout(() => {
                if (monacoEditor) monacoEditor.layout();
                if (monacoEditor2) monacoEditor2.layout();
            }, 50);
            
            const statusZen = document.getElementById('status-zenmode');
            if (statusZen) {
                statusZen.textContent = isZen ? "🧘 Zen: ON" : "🧘 Zen: OFF";
                statusZen.style.color = isZen ? "#3fb950" : "inherit";
            }
            
            showToast(isZen ? "Modo Zen activado" : "Modo Zen desactivado", "info");
        }

        // --- 2. FORMATEADOR DE CÓDIGO OFFLINE ---
        function formatJS(code) {
            try {
                return JSON.stringify(JSON.parse(code), null, 4);
            } catch (e) {}

            let indentLevel = 0;
            const indentStr = '    ';
            const lines = code.split('\n');
            const formattedLines = [];
            
            lines.forEach(line => {
                let trimmed = line.trim();
                if (!trimmed) {
                    formattedLines.push('');
                    return;
                }
                
                let openBraces = (trimmed.match(/\{/g) || []).length;
                let closeBraces = (trimmed.match(/\}/g) || []).length;
                
                if (trimmed.startsWith('}') || trimmed.startsWith(']') || trimmed.startsWith(')')) {
                    indentLevel = Math.max(0, indentLevel - 1);
                } else if (closeBraces > openBraces) {
                    indentLevel = Math.max(0, indentLevel - (closeBraces - openBraces));
                }
                
                formattedLines.push(indentStr.repeat(indentLevel) + trimmed);
                
                if (trimmed.endsWith('{') || trimmed.endsWith('[') || trimmed.endsWith('(')) {
                    indentLevel++;
                } else if (openBraces > closeBraces) {
                    indentLevel += (openBraces - closeBraces);
                }
            });
            return formattedLines.join('\n');
        }

        function formatCSS(code) {
            let indentLevel = 0;
            const indentStr = '    ';
            let cleaned = code
                .replace(/\s*\{\s*/g, ' {\n')
                .replace(/\s*;\s*/g, ';\n')
                .replace(/\s*\}\s*/g, '\n}\n');
                
            const lines = cleaned.split('\n');
            const formattedLines = [];
            
            lines.forEach(line => {
                let trimmed = line.trim();
                if (!trimmed) return;
                
                if (trimmed.startsWith('}')) {
                    indentLevel = Math.max(0, indentLevel - 1);
                }
                
                formattedLines.push(indentStr.repeat(indentLevel) + trimmed);
                
                if (trimmed.endsWith('{')) {
                    indentLevel++;
                }
            });
            return formattedLines.join('\n').replace(/\n\n+/g, '\n');
        }

        function formatHTML(code) {
            let indentLevel = 0;
            const indentStr = '    ';
            let prepared = code
                .replace(/>\s*</g, '>\n<')
                .trim();
                
            const lines = prepared.split('\n');
            const formattedLines = [];
            const selfClosingTags = ['img', 'input', 'br', 'hr', 'meta', 'link', 'source'];
            
            lines.forEach(line => {
                let trimmed = line.trim();
                if (!trimmed) return;
                
                const isClosing = trimmed.startsWith('</');
                const isOpening = trimmed.startsWith('<') && !trimmed.startsWith('</') && !trimmed.startsWith('<!') && !trimmed.endsWith('/>');
                
                let isSelfClosing = false;
                if (isOpening) {
                    const tagNameMatch = trimmed.match(/^<([a-zA-Z0-9\-]+)/);
                    if (tagNameMatch) {
                        const tagName = tagNameMatch[1].toLowerCase();
                        if (selfClosingTags.includes(tagName) || trimmed.endsWith('/>')) {
                            isSelfClosing = true;
                        }
                    }
                }
                
                if (isClosing) {
                    indentLevel = Math.max(0, indentLevel - 1);
                }
                
                formattedLines.push(indentStr.repeat(indentLevel) + trimmed);
                
                if (isOpening && !isSelfClosing) {
                    indentLevel++;
                }
            });
            
            return formattedLines.join('\n');
        }

        function formatCode(code, lang) {
            if (!code) return '';
            lang = (lang || '').toLowerCase();
            
            if (lang === 'json' || lang === 'javascript' || lang === 'js') {
                return formatJS(code);
            } else if (lang === 'css') {
                return formatCSS(code);
            } else if (lang === 'html') {
                return formatHTML(code);
            }
            return code;
        }

        function registerMonacoFormatter() {
            if (typeof loadMonaco === 'function') {
                loadMonaco(() => {
                    if (!window.monaco) return;
                    
                    const languages = ['javascript', 'css', 'html', 'json'];
                    
                    languages.forEach(lang => {
                        if (window.monacoFormattersRegistered) return;
                        
                        monaco.languages.registerDocumentFormattingEditProvider(lang, {
                            provideDocumentFormattingEdits(model, options, token) {
                                const code = model.getValue();
                                const formatted = formatCode(code, lang);
                                return [
                                    {
                                        range: model.getFullModelRange(),
                                        text: formatted
                                    }
                                ];
                            }
                        });
                    });
                    window.monacoFormattersRegistered = true;
                });
            }
        }

        function triggerFormatDocument() {
            if (!extensionsState.formatter?.installed) {
                showToast("Debes instalar la extensión 'Formateador offline' primero.", "warning");
                return;
            }
            
            if (isMonacoLoaded) {
                const editor = (activePane === 1) ? monacoEditor : monacoEditor2;
                if (editor) {
                    editor.trigger('editor', 'editor.action.formatDocument');
                    showToast("Código formateado con éxito (Monaco)", "success");
                }
            } else {
                const ta = document.getElementById('fallback-textarea-' + activePane);
                if (ta && activeFilePath) {
                    const lang = getLanguageFromExtension(activeFilePath);
                    const formatted = formatCode(ta.value, lang);
                    ta.value = formatted;
                    showToast("Código formateado con éxito (Editor Básico)", "success");
                } else {
                    showToast("No hay editor activo para formatear.", "warning");
                }
            }
        }

        // --- 3. TODO TREE SCANNER ---
        function scanDirectoryForTodos(dirPath, results) {
            try {
                const files = fs.readdirSync(dirPath);
                for (const file of files) {
                    const fullPath = path.join(dirPath, file);
                    let stat;
                    try {
                        stat = fs.statSync(fullPath);
                    } catch (err) {
                        continue;
                    }
                    if (stat.isDirectory()) {
                        if (file.startsWith('.') || 
                            file === 'node_modules' || 
                            file === '.git' || 
                            file === '.venv' || 
                            file === '__pycache__' || 
                            file === 'uploads' ||
                            file === 'avatars' ||
                            file === 'docs') {
                            continue;
                        }
                        scanDirectoryForTodos(fullPath, results);
                    } else {
                        const ext = path.extname(file).toLowerCase();
                        if (['.exe', '.png', '.zip', '.gif', '.jpg', '.jpeg', '.pdf', '.mp3', '.mp4', '.sqlite', '.tar', '.gz', '.ico'].includes(ext)) {
                            continue;
                        }
                        if (stat.size > 1 * 1024 * 1024) { // Ignorar archivos mayores a 1MB
                            continue;
                        }
                        
                        try {
                            const content = fs.readFileSync(fullPath, 'utf8');
                            const lines = content.split('\n');
                            lines.forEach((line, idx) => {
                                const trimLine = line.trim();
                                const hasTodo = trimLine.includes('TODO:');
                                const hasFixme = trimLine.includes('FIXME:');
                                if (hasTodo || hasFixme) {
                                    results.push({
                                        filePath: fullPath,
                                        relPath: path.relative(workspaceRoot, fullPath),
                                        lineNum: idx + 1,
                                        type: hasTodo ? 'TODO' : 'FIXME',
                                        content: trimLine
                                    });
                                }
                            });
                        } catch (err) {}
                    }
                }
            } catch (err) {}
        }

        function refreshTodoTree() {
            const container = document.getElementById('todotree-list-container');
            if (!container) return;
            
            container.innerHTML = '<div style="color:#8b949e;padding:8px;text-align:center;">Escaneando...</div>';
            
            const results = [];
            scanDirectoryForTodos(workspaceRoot, results);
            
            if (results.length === 0) {
                container.innerHTML = '<div style="color:#8b949e;padding:8px;text-align:center;">No se encontraron comentarios TODO o FIXME.</div>';
                return;
            }
            
            const groups = {};
            results.forEach(res => {
                if (!groups[res.filePath]) {
                    groups[res.filePath] = {
                        relPath: res.relPath,
                        items: []
                    };
                }
                groups[res.filePath].items.push(res);
            });
            
            container.innerHTML = '';
            
            Object.keys(groups).forEach(filePath => {
                const group = groups[filePath];
                const fileSection = document.createElement('div');
                fileSection.style.cssText = 'margin-bottom: 8px; border: 1px solid #30363d; border-radius: 6px; overflow: hidden;';
                
                const header = document.createElement('div');
                header.style.cssText = 'background: #161b22; padding: 6px 10px; font-weight: bold; font-size: 11px; cursor: pointer; display: flex; justify-content: space-between; align-items: center; user-select: none; color: #c9d1d9;';
                
                const fileBasename = path.basename(filePath);
                header.innerHTML = `
                    <span style="display: flex; align-items: center; gap: 4px;">
                        <span>📂</span>
                        <span title="${group.relPath}">${fileBasename}</span>
                    </span>
                    <span style="background: #30363d; border-radius: 10px; padding: 2px 6px; font-size: 9px; color: #8b949e;">${group.items.length}</span>
                `;
                
                const list = document.createElement('div');
                list.style.cssText = 'display: flex; flex-direction: column; background: #0d1117;';
                
                let expanded = true;
                header.addEventListener('click', () => {
                    expanded = !expanded;
                    list.style.display = expanded ? 'flex' : 'none';
                });
                
                group.items.forEach(item => {
                    const itemEl = document.createElement('div');
                    itemEl.style.cssText = 'padding: 6px 10px; border-bottom: 1px solid #21262d; cursor: pointer; font-size: 11px; display: flex; flex-direction: column; gap: 4px; transition: background 0.2s;';
                    itemEl.addEventListener('mouseenter', () => { itemEl.style.backgroundColor = 'rgba(255, 255, 255, 0.05)'; });
                    itemEl.addEventListener('mouseleave', () => { itemEl.style.backgroundColor = 'transparent'; });
                    
                    const badgeColor = item.type === 'FIXME' ? '#f85149' : '#58a6ff';
                    
                    itemEl.innerHTML = `
                        <div style="display: flex; justify-content: space-between; align-items: center;">
                            <span style="background: ${badgeColor}; color: white; border-radius: 3px; padding: 1px 4px; font-size: 9px; font-weight: bold;">${item.type}</span>
                            <span style="color: #8b949e; font-size: 10px;">Línea ${item.lineNum}</span>
                        </div>
                        <div style="color: #c9d1d9; font-family: monospace; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;" title="${item.content}">${item.content}</div>
                    `;
                    
                    itemEl.addEventListener('click', () => {
                        openFileInEditor(filePath);
                        setTimeout(() => {
                            const editor = (activePane === 1) ? monacoEditor : monacoEditor2;
                            if (isMonacoLoaded && editor) {
                                editor.revealLineInCenter(item.lineNum);
                                editor.setPosition({ lineNumber: item.lineNum, column: 1 });
                                editor.focus();
                            } else {
                                const ta = document.getElementById('fallback-textarea-' + activePane);
                                if (ta) ta.focus();
                            }
                        }, 150);
                    });
                    
                    list.appendChild(itemEl);
                });
                
                if (list.lastChild) {
                    list.lastChild.style.borderBottom = 'none';
                }
                
                fileSection.appendChild(header);
                fileSection.appendChild(list);
                container.appendChild(fileSection);
            });
        }

        // --- 4. TELEMETRÍA (PUENTE GODOT-BLENDER) ---
        function startTelemetryMonitor() {
            if (telemetryInterval) clearInterval(telemetryInterval);
            
            const statusDot = document.getElementById('telemetry-status-dot');
            const tcpStatus = document.getElementById('telemetry-tcp-status');
            const meshCount = document.getElementById('telemetry-mesh-count');
            const vertexCount = document.getElementById('telemetry-vertex-count');
            const lastSync = document.getElementById('telemetry-last-sync');
            const logContainer = document.getElementById('telemetry-log-container');
            
            function addLog(msg) {
                if (!logContainer) return;
                const time = new Date().toLocaleTimeString();
                const logEl = document.createElement('div');
                logEl.innerHTML = `<span style="color:#8b949e;">[${time}]</span> ${msg}`;
                logContainer.appendChild(logEl);
                logContainer.scrollTop = logContainer.scrollHeight;
                while (logContainer.childNodes.length > 50) {
                    logContainer.removeChild(logContainer.firstChild);
                }
            }
            
            telemetryInterval = setInterval(() => {
                if (!extensionsState.telemetry?.installed) {
                    stopTelemetryMonitor();
                    return;
                }
                
                let connected = false;
                
                if (typeof require !== 'undefined' && net && net !== browserNet) {
                    const socket = net.createConnection({ port: 5005, host: '127.0.0.1', timeout: 1000 }, () => {
                        connected = true;
                        socket.end();
                        updateTelemetryUI(true);
                    });
                    
                    socket.on('error', () => {
                        updateTelemetryUI(false);
                    });
                    
                    socket.on('timeout', () => {
                        socket.destroy();
                        updateTelemetryUI(false);
                    });
                } else {
                    const simConnected = Math.random() > 0.4;
                    updateTelemetryUI(simConnected);
                }
                
                function updateTelemetryUI(isConnected) {
                    if (statusDot) {
                        statusDot.style.background = isConnected ? '#3fb950' : '#ff7b72';
                    }
                    if (tcpStatus) {
                        tcpStatus.textContent = isConnected ? 'Conectado (Puerto 5005)' : 'Desconectado';
                        tcpStatus.style.color = isConnected ? '#3fb950' : '#ff7b72';
                    }
                    
                    const telemetryPath = path.join(workspaceRoot, 'blender_telemetry.json');
                    let telemetryData = null;
                    
                    try {
                        if (fs.existsSync(telemetryPath)) {
                            const raw = fs.readFileSync(telemetryPath, 'utf8');
                            telemetryData = JSON.parse(raw);
                        }
                    } catch (e) {}
                    
                    if (telemetryData) {
                        if (meshCount) meshCount.textContent = telemetryData.meshes !== undefined ? telemetryData.meshes : 'Ninguna';
                        if (vertexCount) vertexCount.textContent = telemetryData.vertices !== undefined ? telemetryData.vertices : '0';
                        if (lastSync) lastSync.textContent = telemetryData.lastSyncTime || new Date().toLocaleTimeString();
                        
                        if (telemetryData.message) {
                            addLog(`<span style="color:#58a6ff;">[Sincronización]</span> ${telemetryData.message}`);
                        }
                    } else if (isConnected) {
                        if (typeof require === 'undefined' || net === browserNet) {
                            const randMeshes = Math.floor(Math.random() * 8) + 1;
                            const randVertices = randMeshes * (Math.floor(Math.random() * 400) + 120);
                            const nowStr = new Date().toLocaleTimeString();
                            
                            if (meshCount) meshCount.textContent = randMeshes;
                            if (vertexCount) vertexCount.textContent = randVertices;
                            if (lastSync) lastSync.textContent = nowStr;
                            
                            addLog(`<span style="color:#56d364;">[Simulado]</span> Sincronizadas ${randMeshes} mallas (${randVertices} vértices).`);
                        }
                    }
                }
            }, 3000);
            
            addLog("Servicio de telemetría de puente iniciado.");
        }

        function stopTelemetryMonitor() {
            if (telemetryInterval) {
                clearInterval(telemetryInterval);
                telemetryInterval = null;
            }
            
            const statusDot = document.getElementById('telemetry-status-dot');
            const tcpStatus = document.getElementById('telemetry-tcp-status');
            const meshCount = document.getElementById('telemetry-mesh-count');
            const vertexCount = document.getElementById('telemetry-vertex-count');
            const lastSync = document.getElementById('telemetry-last-sync');
            const logContainer = document.getElementById('telemetry-log-container');
            
            if (statusDot) statusDot.style.background = '#ff7b72';
            if (tcpStatus) {
                tcpStatus.textContent = 'Desconectado';
                tcpStatus.style.color = '#ff7b72';
            }
            if (meshCount) meshCount.textContent = 'Ninguna';
            if (vertexCount) vertexCount.textContent = '0';
            if (lastSync) lastSync.textContent = 'Ninguna';
            if (logContainer) logContainer.innerHTML = '<div style="color: #ff7b72;">[Sistema] Telemetría inactiva.</div>';
        }

        function initExtensions() {
            extensionsState = getExtensionsState();
            updateExtensionsUI();
            
            if (extensionsState.autosave?.installed) startAutosave();
            if (extensionsState.csslinter?.installed) startCSSLinter();
            
            const zenStatus = document.getElementById('status-zenmode');
            if (zenStatus) {
                if (!zenStatus.dataset.listenerBound) {
                    zenStatus.addEventListener('click', () => {
                        toggleZenMode();
                    });
                    zenStatus.dataset.listenerBound = "true";
                }
                if (extensionsState.zenmode?.installed) {
                    zenStatus.style.display = 'inline-flex';
                }
            }
            
            const todoIcon = document.getElementById('btn-sidebar-todotree');
            if (extensionsState.todotree?.installed) {
                if (todoIcon) todoIcon.style.display = 'inline-flex';
            }
            
            const telIcon = document.getElementById('btn-sidebar-telemetry');
            if (extensionsState.telemetry?.installed) {
                if (telIcon) telIcon.style.display = 'inline-flex';
                startTelemetryMonitor();
            }
            
            if (extensionsState.formatter?.installed) {
                registerMonacoFormatter();
            }
        }


        // Cache para el dirty-flag del autoguardado: { [filePath]: lastSavedContent }
        const _autosaveCache = {};

        function startAutosave() {
            const indicator = document.getElementById('status-autosave');
            if (indicator) indicator.style.display = 'inline-flex';

            // Evitar múltiples intervalos apilados
            if (autosaveInterval) clearInterval(autosaveInterval);

            autosaveInterval = setInterval(() => {
                if (!activeFilePath || !openFiles.includes(activeFilePath)) return;
                try {
                    let content = '';
                    if (isMonacoLoaded) {
                        const model = fileModels[activeFilePath];
                        if (model) content = model.getValue();
                    } else {
                        const ta = document.getElementById('fallback-textarea-1') || document.getElementById('fallback-textarea-2');
                        if (ta) content = ta.value;
                    }

                    // Dirty-flag: solo escribir si el contenido cambió desde el último guardado
                    if (!content || _autosaveCache[activeFilePath] === content) return;

                    fs.writeFileSync(activeFilePath, content, 'utf8');
                    _autosaveCache[activeFilePath] = content;

                    // Destello visual en el indicador (sin console.log innecesario)
                    if (indicator) {
                        indicator.style.color = '#7c3aed';
                        setTimeout(() => { indicator.style.color = '#56d364'; }, 800);
                    }
                } catch(e) {
                    console.error('[Nexus] Autosave fallido para', activeFilePath, ':', e.message);
                }
            }, 5000);
        }

        function stopAutosave() {
            const indicator = document.getElementById('status-autosave');
            if (indicator) indicator.style.display = 'none';
            
            if (autosaveInterval) {
                clearInterval(autosaveInterval);
                autosaveInterval = null;
            }
        }

        function startCSSLinter() {
            if (cssLinterInterval) clearInterval(cssLinterInterval);
            
            function runLint() {
                const statusEl = document.getElementById('status-errors');
                if (!statusEl) return;
                
                if (!activeFilePath || !activeFilePath.endsWith('.css')) {
                    statusEl.textContent = '0 errores 0 advertencias';
                    statusEl.style.color = 'white';
                    return;
                }
                
                try {
                    let content = '';
                    if (isMonacoLoaded) {
                        const model = fileModels[activeFilePath];
                        if (model) content = model.getValue();
                    } else {
                        const ta = document.getElementById('fallback-textarea-1') || document.getElementById('fallback-textarea-2');
                        if (ta) content = ta.value;
                    }
                    
                    if (!content) {
                        statusEl.textContent = '0 errores 0 advertencias';
                        statusEl.style.color = 'white';
                        return;
                    }
                    
                    const warnings = [];
                    const lines = content.split('\n');
                    let openBrackets = 0;
                    
                    lines.forEach((line, idx) => {
                        const cleanLine = line.trim();
                        if (!cleanLine || cleanLine.startsWith('/*')) return;
                        
                        if (cleanLine.includes('{')) openBrackets++;
                        if (cleanLine.includes('}')) openBrackets--;
                        
                        if (openBrackets > 0 && cleanLine.includes(':') && !cleanLine.endsWith(';') && !cleanLine.endsWith('{') && !cleanLine.endsWith('}')) {
                            warnings.push(`Línea ${idx + 1}: Falta punto y coma ';'.`);
                        }
                        
                        if (cleanLine.includes('{}')) {
                            warnings.push(`Línea ${idx + 1}: Regla CSS vacía.`);
                        }
                    });
                    
                    if (openBrackets !== 0) {
                        warnings.push(`Llaves desequilibradas en el archivo CSS.`);
                    }
                    
                    if (warnings.length > 0) {
                        statusEl.textContent = `⚠ CSS: ${warnings.length} aviso(s)`;
                        statusEl.style.color = '#ffeb3b';
                        statusEl.title = warnings.join('\n');
                    } else {
                        statusEl.textContent = '0 errores 0 advertencias';
                        statusEl.style.color = 'white';
                        statusEl.title = 'Sintaxis CSS válida';
                    }
                } catch(e) {
                    console.error("Error en CSS Linter: ", e);
                }
            }
            
            cssLinterInterval = setInterval(runLint, 1500);
            runLint();
        }

        function stopCSSLinter() {
            if (cssLinterInterval) {
                clearInterval(cssLinterInterval);
                cssLinterInterval = null;
            }
            const statusEl = document.getElementById('status-errors');
            if (statusEl) {
                statusEl.textContent = '0 errores 0 advertencias';
                statusEl.style.color = 'white';
                statusEl.title = '';
            }
        }

