        function getIconForFile(fileName) {
            const ext = fileName.split('.').pop().toLowerCase();
            if (fileName === 'package.json' || fileName === 'package-lock.json') return '⚙️';
            if (fileName === 'index.html' || ext === 'html' || ext === 'htm') return '🌐';
            if (ext === 'js' || ext === 'ts') return '🟨';
            if (ext === 'css') return '🎨';
            if (ext === 'py') return '🐍';
            if (ext === 'json') return '⚙️';
            if (ext === 'md') return '📝';
            if (ext === 'png' || ext === 'jpg' || ext === 'jpeg' || ext === 'gif' || ext === 'svg') return '🖼️';
            return '📄';
        }

