        function detectLanguage(filename) {
          if (!filename) return { id:'plaintext', name:'Texto', color:'#6b7280', icon:'📄' };
          const ext = filename.toLowerCase().split('.').pop();
          if (filename.toLowerCase() === 'dockerfile') return LANGUAGE_MAP['dockerfile'];
          return LANGUAGE_MAP[ext] || { id:'plaintext', name:ext.toUpperCase(), color:'#6b7280', icon:'📄' };
        }

        function getLanguageFromExtension(filePath) {
            return detectLanguage(filePath).id;
        }

