        function openNewProjectTemplateModal() {
          if (NexusWindowManager.windows['nexus-win-project-templates']) {
            NexusWindowManager.windows['nexus-win-project-templates'].restore();
            NexusWindowManager.windows['nexus-win-project-templates'].focus();
            return;
          }

          let cardsHtml = '';
          PROJECT_TEMPLATES.forEach(temp => {
            cardsHtml += `
              <div class="template-card" onclick="selectTemplate('${temp.id}')" style="
                background: #161b22;
                border: 1px solid #30363d;
                border-radius: 8px;
                padding: 16px;
                cursor: pointer;
                transition: all 0.2s ease;
                display: flex;
                flex-direction: column;
                gap: 8px;
              ">
                <div style="font-size: 24px;">${temp.name.split(' ')[0]}</div>
                <div style="font-size: 14px; font-weight: bold; color: #e6edf3;">${temp.name.split(' ').slice(1).join(' ')}</div>
                <div style="font-size: 11px; color: #8b949e; line-height: 1.4; flex: 1;">${temp.desc}</div>
                <div style="font-size: 10px; color: #7c3aed; font-family: monospace; margin-top: 8px;">
                  ${temp.files.length} archivo(s)
                </div>
              </div>
            `;
          });

          const content = `
            <div style="display: flex; flex-direction: column; height: 100%; background: #0d1117; color: #e6edf3; font-family: 'Segoe UI', system-ui, sans-serif; overflow: hidden;">
              <style>
                .template-card:hover {
                  border-color: #7c3aed !important;
                  transform: translateY(-2px);
                  box-shadow: 0 8px 24px rgba(124, 58, 237, 0.15);
                  background: #21262d !important;
                }
              </style>
              <div style="padding: 16px; border-bottom: 1px solid #30363d; display: flex; justify-content: space-between; align-items: center;">
                <div>
                  <h2 style="font-size: 16px; font-weight: 600; margin: 0; color: #e6edf3;">Selecciona una Plantilla</h2>
                  <p style="font-size: 12px; color: #8b949e; margin: 4px 0 0 0;">Crea un proyecto estructurado al instante con configuraciones predefinidas</p>
                </div>
              </div>
              <div style="flex: 1; padding: 20px; overflow-y: auto;">
                <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(180px, 1fr)); gap: 16px;">
                  ${cardsHtml}
                </div>
              </div>
            </div>
          `;

          new NexusWindow({
            id: 'nexus-win-project-templates',
            title: 'Nuevo Proyecto desde Plantilla',
            icon: '📁',
            width: 680,
            height: 480,
            content
          });

          window.selectTemplate = (templateId) => {
            const temp = PROJECT_TEMPLATES.find(t => t.id === templateId);
            if (!temp) return;
            
            showCreateFolderPrompt(
              `Crear Proyecto: ${temp.name}`,
              templateId,
              (result) => {
                if (!result) return;
                createProjectFromTemplate(temp, result.name, result.parentDir, result.openWorkspace);
              }
            );
          };
        }

        function createProjectFromTemplate(template, projectName, parentDir, openWorkspace = true) {
          const baseDir = parentDir || workspaceRoot;
          const projectPath = path.join(baseDir, projectName);
          try {
            if (typeof fs !== 'undefined') {
              if (fs.existsSync(projectPath)) {
                showToast("La carpeta del proyecto ya existe", "warning");
                return;
              }
              
              fs.mkdirSync(projectPath, { recursive: true });
              
              template.files.forEach(f => {
                const filePath = path.join(projectPath, f.name);
                const fileDir = path.dirname(filePath);
                if (!fs.existsSync(fileDir)) {
                  fs.mkdirSync(fileDir, { recursive: true });
                }
                fs.writeFileSync(filePath, f.content, 'utf8');
              });
              
              showToast(`Proyecto '${projectName}' creado a partir de plantilla '${template.name}'`, "success");
              
              const win = NexusWindowManager.windows['nexus-win-project-templates'];
              if (win) win.close();
              
              if (openWorkspace) {
                window.changeWorkspace(projectPath);
                window.closeProjectDashboard();
              } else {
                renderExplorer();
              }
              
              if (template.files.length > 0) {
                const firstFilePath = path.join(projectPath, template.files[0].name);
                openFileInEditor(firstFilePath);
              }
            }
          } catch (err) {
            showToast("Error al crear proyecto: " + err.message, "error");
          }
        }

        // ─── Helpers de registro de proyectos ───────────────────────────────────
        window.getNexusProjects = function() {
          try { return JSON.parse(localStorage.getItem('nexus_projects') || '[]'); } catch { return []; }
        };
        window.saveNexusProjects = function(list) {
          localStorage.setItem('nexus_projects', JSON.stringify(list));
        };
        window.getCurrentProjectType = function() {
          if (!workspaceRoot) return 'code';
          const list = window.getNexusProjects();
          const current = list.find(p => p.path === workspaceRoot);
          return current ? current.type : 'code';
        };
        // Registra un proyecto en la lista curada (idempotente por path)
        window.registerProject = function(projectPath, type, projectName) {
          const _req = window.nodeRequire || window.require || (typeof require !== 'undefined' ? require : null);
          const _path = _req ? _req('path') : null;
          const list = window.getNexusProjects();
          const existing = list.find(p => p.path === projectPath);
          if (existing) {
            existing.lastOpened = Date.now();
            if (type) existing.type = type;
          } else {
            list.unshift({
              path: projectPath,
              name: projectName || (_path ? _path.basename(projectPath) : projectPath),
              type: type || 'code',
              lastOpened: Date.now()
            });
          }
          window.saveNexusProjects(list);
        };

        function openProjectDashboardModal() {
          const req = window.nodeRequire || window.require || (typeof require !== 'undefined' ? require : null);
          const fs = req ? req('fs') : null;
          const path = req ? req('path') : null;

          // Asegurar que el workspace activo esté registrado en la lista curada
          if (workspaceRoot) window.registerProject(workspaceRoot);

          // Lista curada de proyectos (sólo los que el usuario creó/abrió explícitamente)
          let allProjects = window.getNexusProjects();

          const TYPE_META = {
            web:  { label: 'Web',    color: '#38bdf8', rgb: '56,189,248',  icon: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg>` },
            game: { label: 'Juego',  color: '#a78bfa', rgb: '167,139,250', icon: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="2" y="6" width="20" height="12" rx="2"/><path d="M6 12h4M8 10v4M15 12h2M18 10v4"/></svg>` },
            code: { label: 'Código', color: '#34d399', rgb: '52,211,153',  icon: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/></svg>` },
          };

          function renderDashboardContent() {
            let listHtml = '';

            if (allProjects.length === 0) {
              listHtml = `
                <div style="text-align:center;padding:60px 20px;color:#8b949e;">
                  <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#30363d" stroke-width="1.5" style="display:block;margin:0 auto 16px;"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>
                  <div style="font-size:14px;font-weight:600;color:#e6edf3;margin-bottom:8px;">Sin proyectos registrados</div>
                  <div style="font-size:12px;">Crea un nuevo proyecto o abre una carpeta existente para empezar.</div>
                </div>`;
            } else {
              allProjects.forEach(proj => {
                const isCurrent = proj.path === workspaceRoot;
                const escPath = proj.path.replace(/\\/g, '/');
                const meta = TYPE_META[proj.type] || TYPE_META.code;
                const lastDate = proj.lastOpened ? new Date(proj.lastOpened).toLocaleDateString() : '—';
                let exists = true;
                try { if (fs) exists = fs.existsSync(proj.path); } catch {}

                listHtml += `
                  <div class="project-item" style="
                    background:${isCurrent ? 'rgba(124,58,237,0.08)' : '#161b22'};
                    border:1px solid ${isCurrent ? '#7c3aed' : '#30363d'};
                    border-radius:10px;padding:14px 16px;
                    display:flex;align-items:center;justify-content:space-between;
                    gap:12px;transition:all 0.2s ease;margin-bottom:8px;
                  " data-path="${escPath}">
                    <div style="flex:1;min-width:0;display:flex;align-items:center;gap:14px;">
                      <div style="width:38px;height:38px;border-radius:8px;flex-shrink:0;
                        background:rgba(${meta.rgb},0.12);color:${meta.color};
                        display:flex;align-items:center;justify-content:center;
                        border:1px solid rgba(${meta.rgb},0.25);">${meta.icon}</div>
                      <div style="min-width:0;">
                        <div style="font-size:13px;font-weight:600;color:#e6edf3;display:flex;align-items:center;gap:7px;margin-bottom:3px;">
                          <span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${proj.name}</span>
                          ${isCurrent ? '<span style="font-size:9px;background:rgba(124,58,237,0.2);color:#a5d6ff;padding:1px 7px;border-radius:10px;border:1px solid rgba(124,58,237,0.4);flex-shrink:0;">Activo</span>' : ''}
                          <span style="font-size:9px;background:rgba(${meta.rgb},0.1);color:${meta.color};padding:1px 7px;border-radius:10px;flex-shrink:0;">${meta.label}</span>
                          ${!exists ? '<span style="font-size:9px;background:rgba(255,123,114,0.1);color:#ff7b72;padding:1px 7px;border-radius:10px;flex-shrink:0;">No encontrado</span>' : ''}
                        </div>
                        <div style="font-size:10px;color:#8b949e;font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${proj.path}">${proj.path}</div>
                        <div style="font-size:10px;color:#6e7681;margin-top:3px;">Abierto: ${lastDate}</div>
                      </div>
                    </div>
                    <div style="display:flex;align-items:center;gap:6px;flex-shrink:0;">
                      ${!isCurrent ? `<button onclick="window.switchProject('${escPath}')" style="
                        background:#21262d;border:1px solid #30363d;border-radius:6px;
                        color:#c9d1d9;padding:5px 12px;font-size:11px;font-weight:600;
                        cursor:pointer;transition:all 0.2s;"
                        onmouseover="this.style.borderColor='#7c3aed';this.style.color='#7c3aed';"
                        onmouseout="this.style.borderColor='#30363d';this.style.color='#c9d1d9';">Abrir</button>` : ''}
                      <button onclick="window.removeNexusProject('${escPath}',event)" style="
                        background:transparent;border:none;color:#ff7b72;font-size:13px;
                        cursor:pointer;padding:4px 6px;opacity:0.5;transition:opacity 0.2s;line-height:1;"
                        onmouseover="this.style.opacity='1';" onmouseout="this.style.opacity='0.5';" title="Quitar de la lista">✕</button>
                    </div>
                  </div>`;
              });
            }

            // IAs Conectadas
            const allProvidersList = [
              { id: 'openai', name: 'OpenAI' }, { id: 'anthropic', name: 'Anthropic' },
              { id: 'google', name: 'Google AI' }, { id: 'groq', name: 'Groq' },
              { id: 'mistral', name: 'Mistral' }, { id: 'deepseek', name: 'DeepSeek' },
              { id: 'moonshot', name: 'Moonshot' }, { id: 'xai', name: 'xAI' },
              { id: 'openrouter', name: 'OpenRouter' },
              { id: 'together', name: 'Together AI' }, { id: 'perplexity', name: 'Perplexity' },
              { id: 'fireworks', name: 'Fireworks' }, { id: 'cerebras', name: 'Cerebras' },
              { id: 'ollama', name: 'Ollama' }, { id: 'lmstudio', name: 'LM Studio' },
              { id: 'jan', name: 'Jan' }, { id: 'llamacpp', name: 'llama.cpp' }, { id: 'vllm', name: 'vLLM' }
            ];
            let iasHtml = '';
            allProvidersList.forEach(p => {
              const isConn = LOCAL_AI_PROVIDERS.has(p.id)
                ? !!(apiKeysState[p.id] || localStorage.getItem(localUrlKey(p.id)))
                : !!(apiKeysState[p.id] && apiKeysState[p.id].key);
              iasHtml += `<div style="display:inline-flex;align-items:center;gap:5px;font-size:10px;
                background:${isConn ? 'rgba(16,185,129,0.1)' : 'rgba(255,255,255,0.03)'};
                color:${isConn ? '#10b981' : '#8b949e'};padding:3px 8px;border-radius:10px;
                border:1px solid ${isConn ? 'rgba(16,185,129,0.25)' : 'rgba(255,255,255,0.05)'};
                opacity:${isConn ? '1' : '0.5'};" title="${isConn ? 'Conectada' : 'Sin API Key'}">
                <span style="width:5px;height:5px;background:${isConn ? '#10b981' : '#4b5563'};border-radius:50%;display:inline-block;"></span>
                ${p.name}</div>`;
            });

            return `
              <div style="display:flex;flex-direction:column;height:100%;background:#0d1117;color:#e6edf3;font-family:'Segoe UI',system-ui,sans-serif;overflow:hidden;">
                <style>
                  .project-item:hover{border-color:#7c3aed!important;background:rgba(22,27,34,0.9)!important;box-shadow:0 4px 16px rgba(124,58,237,0.1);}
                  .dash-btn{display:flex;align-items:center;gap:8px;background:#21262d;border:1px solid #30363d;border-radius:6px;color:#c9d1d9;padding:8px 14px;font-size:12px;font-weight:600;cursor:pointer;transition:all 0.2s;}
                  .dash-btn:hover{border-color:#7c3aed;background:#30363d;color:#e6edf3;transform:translateY(-1px);}
                  .dash-primary-btn{background:#7c3aed;border-color:#904dfb;color:#fff;}
                  .dash-primary-btn:hover{background:#6d28d9;border-color:#7c3aed;color:#fff;}
                </style>
                <div style="padding:18px 20px;border-bottom:1px solid #30363d;background:linear-gradient(135deg,rgba(124,58,237,0.1) 0%,transparent 100%);display:flex;justify-content:space-between;align-items:center;">
                  <div>
                    <h2 style="font-size:17px;font-weight:700;margin:0;color:#e6edf3;display:flex;align-items:center;gap:10px;">
                      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#7c3aed" stroke-width="2"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>
                      Inicio &amp; Proyectos
                    </h2>
                    <p style="font-size:11px;color:#8b949e;margin:3px 0 0 0;">Gestiona y alterna entre tus proyectos</p>
                  </div>
                  <div style="display:flex;gap:8px;align-items:center;">
                    <button class="dash-btn" onclick="window.createNewProjectFolderPrompt()">
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
                      Nuevo Proyecto
                    </button>
                    <button class="dash-btn" onclick="openNewProjectTemplateModal()">
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M13 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V9z"/><polyline points="13 2 13 9 20 9"/></svg>
                      Plantilla
                    </button>
                    <button class="dash-btn" onclick="window.selectWorkspaceFolder()">
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>
                      Abrir Carpeta
                    </button>
                    <button class="dash-btn dash-primary-btn" onclick="window.closeProjectDashboard()" style="background:#238636;border-color:#2ea44f;">
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/></svg>
                      Ir al Editor
                    </button>
                  </div>
                </div>
                <div style="flex:1;display:flex;overflow:hidden;">
                  <!-- Sidebar -->
                  <div style="width:240px;border-right:1px solid #30363d;padding:18px;display:flex;flex-direction:column;gap:14px;background:rgba(22,27,34,0.3);">
                    <div>
                      <span style="font-size:10px;font-weight:700;color:#8b949e;text-transform:uppercase;letter-spacing:0.05em;">Proyecto Activo</span>
                      <div style="font-size:15px;font-weight:700;color:#7c3aed;margin-top:5px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${path ? (path.basename(workspaceRoot) || workspaceRoot) : workspaceRoot}</div>
                      <div style="font-size:10px;color:#8b949e;word-break:break-all;margin-top:3px;font-family:monospace;">${workspaceRoot}</div>
                    </div>
                    <div style="border-top:1px solid #30363d;padding-top:14px;">
                      <span style="font-size:10px;font-weight:700;color:#8b949e;text-transform:uppercase;letter-spacing:0.05em;display:block;margin-bottom:8px;">IAs Conectadas</span>
                      <div style="display:flex;flex-wrap:wrap;gap:5px;">${iasHtml}</div>
                    </div>
                    <div style="margin-top:auto;border-top:1px solid #30363d;padding-top:12px;">
                      <button onclick="window.downloadDesktopExecutable()" class="dash-btn" style="width:100%;justify-content:center;background:linear-gradient(135deg,#10b981,#059669);border:none;color:#fff;font-weight:700;font-size:11px;">
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
                        Descargar Ejecutable
                      </button>
                      <div style="font-size:9px;color:#8b949e;text-align:center;margin-top:8px;">
                        Atajo: <kbd style="background:#21262d;padding:2px 5px;border-radius:4px;border:1px solid #30363d;font-family:monospace;font-size:9px;color:#c9d1d9;">Ctrl+Alt+P</kbd>
                      </div>
                    </div>
                  </div>
                  <!-- Lista de proyectos -->
                  <div style="flex:1;padding:18px;overflow-y:auto;display:flex;flex-direction:column;">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
                      <span style="font-size:10px;font-weight:700;color:#8b949e;text-transform:uppercase;letter-spacing:0.05em;">Mis Proyectos</span>
                      <span style="font-size:10px;color:#8b949e;">${allProjects.length} proyecto${allProjects.length !== 1 ? 's' : ''}</span>
                    </div>
                    ${listHtml}
                  </div>
                </div>
              </div>
            `;
          }


          const container = document.getElementById('nexus-home-content');
          if (container) {
            container.innerHTML = renderDashboardContent();
          }

          const homeScreen = document.getElementById('nexus-home-screen');
          if (homeScreen) {
            homeScreen.style.display = 'flex';
            setTimeout(() => { homeScreen.style.opacity = '1'; }, 50);
          }

          window.closeProjectDashboard = () => {
            if (homeScreen) {
              homeScreen.style.opacity = '0';
              setTimeout(() => { homeScreen.style.display = 'none'; }, 300);
            }
          };

          window.downloadDesktopExecutable = () => {
            const url = 'https://github.com/Sencans/nexus-ide/releases';
            const reqElec = window.nodeRequire || window.require || (typeof require !== 'undefined' ? require : null);
            if (reqElec) {
              try {
                reqElec('electron').shell.openExternal(url);
              } catch(e) {
                window.open(url, '_blank');
              }
            } else {
              window.open(url, '_blank');
            }
          };

          window.switchProject = (projPath) => {
            let currentHistory = [];
            try {
              currentHistory = JSON.parse(localStorage.getItem('nexus_projects_history') || '[]');
            } catch(e) {
              currentHistory = [];
            }
            if (!currentHistory.includes(projPath)) {
              currentHistory.unshift(projPath);
              localStorage.setItem('nexus_projects_history', JSON.stringify(currentHistory));
            }
            if (window.changeWorkspace) {
              window.changeWorkspace(projPath);
            }
            window.closeProjectDashboard();
          };

          window.removeNexusProject = (projPath, e) => {
            if (e) e.stopPropagation();
            const list = window.getNexusProjects().filter(p => p.path !== projPath);
            window.saveNexusProjects(list);
            allProjects = list;
            if (container) container.innerHTML = renderDashboardContent();
          };
          // Legacy alias por compatibilidad con código antiguo
          window.removeProjectFromHistory = window.removeNexusProject;

          window.createNewProjectFolderPrompt = () => {
            // ── Paso 1: seleccionar tipo de proyecto ─────────────────────────────────
            const overlay = document.createElement('div');
            overlay.style.cssText = `
              position:fixed;inset:0;background:rgba(0,0,0,0.72);
              display:flex;align-items:center;justify-content:center;
              z-index:25000;backdrop-filter:blur(4px);
              animation:fadeIn 0.18s ease;
            `;

            const types = [
              {
                id: 'web',
                label: 'Web',
                desc: 'HTML, CSS, JS, React, Vue…',
                color: '#38bdf8', rgb: '56,189,248',
                icon: `<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                  <circle cx="12" cy="12" r="10"/>
                  <path d="M2 12h20M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/>
                </svg>`
              },
              {
                id: 'code',
                label: 'Código',
                desc: 'Python, C++, Rust, Go…',
                color: '#34d399', rgb: '52,211,153',
                icon: `<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                  <polyline points="16 18 22 12 16 6"/>
                  <polyline points="8 6 2 12 8 18"/>
                </svg>`
              },
              {
                id: 'game',
                label: 'Juego',
                desc: 'Godot, Unity, Phaser…',
                color: '#a78bfa', rgb: '167,139,250',
                icon: `<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                  <rect x="2" y="6" width="20" height="12" rx="2"/>
                  <path d="M6 12h4M8 10v4M15 12h2M18 10v4"/>
                </svg>`
              }
            ];

            let selectedType = null;

            const modal = document.createElement('div');
            modal.style.cssText = `
              background:#161b22;border:1px solid #30363d;border-radius:14px;
              padding:28px;width:500px;max-width:94vw;
              box-shadow:0 24px 64px rgba(0,0,0,0.5);
              animation:slideUp 0.22s cubic-bezier(.22,1,.36,1);
            `;

            // Add keyframe animations once
            if (!document.getElementById('wizard-anim-style')) {
              const s = document.createElement('style');
              s.id = 'wizard-anim-style';
              s.textContent = `
                @keyframes fadeIn{from{opacity:0}to{opacity:1}}
                @keyframes slideUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
                .wiz-type-card{
                  flex:1;padding:20px 14px;border:1.5px solid #30363d;border-radius:10px;
                  background:#0d1117;cursor:pointer;display:flex;flex-direction:column;
                  align-items:center;gap:10px;transition:all 0.18s ease;text-align:center;
                }
                .wiz-type-card:hover{transform:translateY(-3px);box-shadow:0 8px 24px rgba(0,0,0,0.4);}
                .wiz-type-card.selected{box-shadow:0 0 0 2px var(--card-color,#7c3aed);}
              `;
              document.head.appendChild(s);
            }

            modal.innerHTML = `
              <div style="display:flex;align-items:center;gap:12px;margin-bottom:6px;">
                <div style="width:32px;height:32px;border-radius:8px;background:rgba(124,58,237,0.15);
                  display:flex;align-items:center;justify-content:center;color:#7c3aed;">
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
                  </svg>
                </div>
                <div>
                  <div style="font-size:16px;font-weight:700;color:#e6edf3;">Nuevo Proyecto</div>
                  <div style="font-size:11px;color:#8b949e;">Paso 1 de 2 — Selecciona el tipo</div>
                </div>
              </div>

              <div style="height:1px;background:#30363d;margin:16px 0;"></div>

              <div id="wiz-type-grid" style="display:flex;gap:12px;margin-bottom:20px;"></div>

              <div style="display:flex;gap:8px;justify-content:flex-end;">
                <button id="wiz-cancel" style="
                  background:#21262d;border:1px solid #30363d;border-radius:6px;
                  color:#c9d1d9;padding:8px 16px;font-size:13px;cursor:pointer;
                  font-family:inherit;transition:background 0.15s;
                ">Cancelar</button>
                <button id="wiz-next" disabled style="
                  background:#7c3aed;border:1px solid #904dfb;border-radius:6px;
                  color:#fff;padding:8px 20px;font-size:13px;cursor:pointer;
                  font-family:inherit;font-weight:600;transition:all 0.15s;
                  opacity:0.45;
                ">Siguiente →</button>
              </div>
            `;

            // Populate type cards
            const grid = modal.querySelector('#wiz-type-grid');
            types.forEach(t => {
              const card = document.createElement('div');
              card.className = 'wiz-type-card';
              card.style.setProperty('--card-color', t.color);
              card.innerHTML = `
                <div style="color:${t.color};width:48px;height:48px;border-radius:12px;
                  background:rgba(${t.rgb},0.1);display:flex;align-items:center;
                  justify-content:center;border:1px solid rgba(${t.rgb},0.2);">
                  ${t.icon}
                </div>
                <div style="font-size:13px;font-weight:700;color:#e6edf3;">${t.label}</div>
                <div style="font-size:11px;color:#8b949e;line-height:1.4;">${t.desc}</div>
              `;
              card.onclick = () => {
                grid.querySelectorAll('.wiz-type-card').forEach(c => {
                  c.classList.remove('selected');
                  c.style.borderColor = '#30363d';
                  c.style.background = '#0d1117';
                });
                card.classList.add('selected');
                card.style.borderColor = t.color;
                card.style.background = `rgba(${t.rgb},0.06)`;
                selectedType = t.id;
                const nextBtn = modal.querySelector('#wiz-next');
                nextBtn.disabled = false;
                nextBtn.style.opacity = '1';
              };
              grid.appendChild(card);
            });

            const cancelBtn = modal.querySelector('#wiz-cancel');
            const nextBtn   = modal.querySelector('#wiz-next');

            cancelBtn.onmouseover = () => cancelBtn.style.background = '#30363d';
            cancelBtn.onmouseout  = () => cancelBtn.style.background = '#21262d';

            cancelBtn.onclick = () => overlay.remove();
            overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

            nextBtn.onclick = () => {
              if (!selectedType) return;
              overlay.remove();

              // ── Paso 2: nombre y ubicación usando modal existente ─────────────────
              showCreateFolderPrompt(
                `Nuevo Proyecto ${types.find(t=>t.id===selectedType).label}`,
                'mi-nuevo-proyecto',
                (result) => {
                  if (!result) return;
                  const { name, parentDir, openWorkspace } = result;
                  try {
                    const newPath = path ? path.join(parentDir, name) : name;
                    if (fs && fs.existsSync(newPath)) {
                      showToast('La carpeta ya existe', 'warning');
                      return;
                    }
                    if (fs) fs.mkdirSync(newPath, { recursive: true });
                    // Registrar con tipo seleccionado
                    window.registerProject(newPath, selectedType, name);
                    showToast(`Proyecto '${name}' creado`, 'success');
                    if (openWorkspace) {
                      window.changeWorkspace(newPath);
                      window.closeProjectDashboard();
                    } else {
                      const cont = document.getElementById('nexus-home-content');
                      if (cont) cont.innerHTML = renderDashboardContent();
                      renderExplorer();
                    }
                  } catch(e) {
                    showToast('Error al crear proyecto: ' + e.message, 'error');
                  }
                }
              );
            };

            overlay.appendChild(modal);
            document.body.appendChild(overlay);
          };

        }

        
        // ==========================================
        // SISTEMA DE HABILIDADES DE IA (AI SKILLS)
        // ==========================================
        window.getSkills = function() {
            if (typeof fs === 'undefined' || typeof workspaceRoot === 'undefined') return [];
            const skillsDir = path.join(workspaceRoot, 'skills');
            if (!fs.existsSync(skillsDir)) {
                try {
                    fs.mkdirSync(skillsDir, { recursive: true });
                } catch(e) {
                    console.error("Error al crear carpeta de skills:", e);
                    return [];
                }
            }
            try {
                const files = fs.readdirSync(skillsDir);
                const skills = [];
                files.forEach(file => {
                    if (file.endsWith('.json')) {
                        try {
                            const data = JSON.parse(fs.readFileSync(path.join(skillsDir, file), 'utf8'));
                            skills.push(data);
                        } catch(err) {
                            console.error("Error al leer skill file: " + file, err);
                        }
                    }
                });
                return skills;
            } catch(e) {
                console.error("Error al listar skills:", e);
                return [];
            }
        };

        window.saveSkill = function(skill) {
            if (typeof fs === 'undefined' || typeof workspaceRoot === 'undefined') return;
            const skillsDir = path.join(workspaceRoot, 'skills');
            if (!fs.existsSync(skillsDir)) {
                fs.mkdirSync(skillsDir, { recursive: true });
            }
            const skillPath = path.join(skillsDir, `${skill.id}.json`);
            fs.writeFileSync(skillPath, JSON.stringify(skill, null, 4), 'utf8');
            
            if (skill.scriptCode) {
                const ext = (skill.commandTemplate && skill.commandTemplate.includes('node')) ? '.js' : '.py';
                const scriptPath = path.join(skillsDir, `${skill.id}${ext}`);
                fs.writeFileSync(scriptPath, skill.scriptCode, 'utf8');
            }
        };

        window.deleteSkill = function(skillId) {
            if (typeof fs === 'undefined' || typeof workspaceRoot === 'undefined') return;
            const skillsDir = path.join(workspaceRoot, 'skills');
            const skillPath = path.join(skillsDir, `${skillId}.json`);
            if (fs.existsSync(skillPath)) {
                fs.unlinkSync(skillPath);
            }
            ['.py', '.js'].forEach(ext => {
                const scriptPath = path.join(skillsDir, `${skillId}${ext}`);
                if (fs.existsSync(scriptPath)) {
                    fs.unlinkSync(scriptPath);
                }
            });
        };

        window.refreshSkillsUI = function() {
            const container = document.getElementById('skills-list-container');
            if (!container) return;
            
            const skills = window.getSkills();
            if (skills.length === 0) {
                container.innerHTML = `
                    <div style="color:#8b949e; text-align:center; font-size:11px; padding:20px; border: 1px dashed #30363d; border-radius:6px; background:#161b22; margin-top:10px;">
                        No hay habilidades personalizadas. ¡Crea una nueva para entrenar a tu IA!
                    </div>
                `;
                return;
            }
            
            container.innerHTML = '';
            skills.forEach(skill => {
                const card = document.createElement('div');
                card.style.cssText = 'background:#161b22; border:1px solid #30363d; border-radius:6px; padding:10px; display:flex; flex-direction:column; gap:6px; position:relative;';
                
                const isChecked = skill.enabled ? 'checked' : '';
                
                card.innerHTML = `
                    <div style="display:flex; justify-content:space-between; align-items:center;">
                        <span style="font-weight:bold; font-size:12px; color:#e6edf3; display:flex; align-items:center; gap:6px;">
                            🪄 ${skill.name}
                        </span>
                        <label class="switch" style="position:relative; display:inline-block; width:28px; height:16px; margin:0;">
                            <input type="checkbox" id="skill-toggle-${skill.id}" ${isChecked} style="opacity:0; width:0; height:0;">
                            <span class="slider" style="position:absolute; cursor:pointer; top:0; left:0; right:0; bottom:0; background-color:#333; border-radius:16px; transition:.3s;"></span>
                        </label>
                    </div>
                    <div style="font-size:10px; color:#8b949e; line-height:1.4;">${skill.description}</div>
                    <div style="font-size:9px; color:#58a6ff; font-family:monospace; background:#0d1117; padding:2px 6px; border-radius:3px; align-self:flex-start;">
                        ID: ${skill.id}
                    </div>
                    <div style="display:flex; gap:8px; margin-top:4px; border-top:1px solid #21262d; padding-top:6px; justify-content:flex-end;">
                        <button onclick="window.openSkillEditorModal('${skill.id}')" style="background:none; border:none; color:#58a6ff; cursor:pointer; font-size:10px; padding:0; font-family:inherit;">Editar</button>
                        <button onclick="window.confirmDeleteSkill('${skill.id}')" style="background:none; border:none; color:#f85149; cursor:pointer; font-size:10px; padding:0; font-family:inherit;">Eliminar</button>
                    </div>
                `;
                
                container.appendChild(card);
                
                const input = card.querySelector(`#skill-toggle-${skill.id}`);
                const slider = card.querySelector('.slider');
                
                const updateSliderColor = (checked) => {
                    slider.style.backgroundColor = checked ? '#7c3aed' : '#333';
                };
                updateSliderColor(skill.enabled);
                
                input.addEventListener('change', (e) => {
                    skill.enabled = e.target.checked;
                    updateSliderColor(e.target.checked);
                    window.saveSkill(skill);
                    showToast("Habilidad " + skill.name + (skill.enabled ? " activada" : " desactivada"), "info");
                });
            });
        };

        window.confirmDeleteSkill = (skillId) => {
            if (confirm("¿Estás seguro de que deseas eliminar la habilidad '" + skillId + "'?")) {
                window.deleteSkill(skillId);
                showToast("Habilidad eliminada", "info");
                window.refreshSkillsUI();
                renderExplorer();
            }
        };

        window.importSkillFile = function(input) {
            if (!input.files || input.files.length === 0) return;
            const file = input.files[0];
            
            if (file.path && typeof fs !== 'undefined') {
                try {
                    const skill = JSON.parse(fs.readFileSync(file.path, 'utf8'));
                    if (!skill.id || !skill.name || !skill.systemPrompt) {
                        showToast("El archivo no es una habilidad de Nexus válida.", "error");
                        return;
                    }
                    
                    window.saveSkill(skill);
                    
                    const srcDir = path.dirname(file.path);
                    ['.py', '.js'].forEach(ext => {
                        const scriptSrc = path.join(srcDir, skill.id + ext);
                        if (fs.existsSync(scriptSrc)) {
                            const scriptDest = path.join(workspaceRoot, 'skills', skill.id + ext);
                            fs.copyFileSync(scriptSrc, scriptDest);
                        }
                    });
                    
                    showToast("Habilidad '" + skill.name + "' importada correctamente.", "success");
                    window.refreshSkillsUI();
                    renderExplorer();
                } catch(e) {
                    showToast("Error al importar la habilidad: " + e.message, "error");
                }
            } else {
                const reader = new FileReader();
                reader.onload = function(e) {
                    try {
                        const skill = JSON.parse(e.target.result);
                        if (!skill.id || !skill.name || !skill.systemPrompt) {
                            showToast("El archivo no es una habilidad de Nexus válida.", "error");
                            return;
                        }
                        window.saveSkill(skill);
                        showToast("Habilidad '" + skill.name + "' importada correctamente.", "success");
                        window.refreshSkillsUI();
                        renderExplorer();
                    } catch(err) {
                        showToast("Error al leer el archivo JSON: " + err.message, "error");
                    }
                };
                reader.readAsText(file);
            }
            input.value = '';
        };

        window.highlightErrorInEditor = function(filePath, lineNum, message) {
            if (!filePath || !lineNum) return;
            
            let absolutePath = filePath;
            if (typeof path !== 'undefined' && !path.isAbsolute(absolutePath)) {
                absolutePath = path.resolve(workspaceRoot, absolutePath);
            }
            
            if (typeof fs !== 'undefined' && fs.existsSync(absolutePath)) {
                openFileInEditor(absolutePath);
                showToast(message + " detectado en la línea " + lineNum, "error");
                
                setTimeout(() => {
                    if (isMonacoLoaded && monacoEditor) {
                        monacoEditor.revealLineInCenter(lineNum);
                        monacoEditor.setPosition({ lineNumber: lineNum, column: 1 });
                        
                        const decorations = monacoEditor.deltaDecorations([], [
                            {
                                range: new monaco.Range(lineNum, 1, lineNum, 1),
                                options: {
                                    isWholeLine: true,
                                    className: 'error-line-highlight',
                                    glyphMarginClassName: 'error-glyph-margin',
                                    hoverMessage: { value: "**" + message + "**\n\nLínea " + lineNum }
                                }
                            }
                        ]);
                        
                        setTimeout(() => {
                            monacoEditor.deltaDecorations(decorations, []);
                        }, 8000);
                    }
                }, 400);
            }
        };

        window.checkForErrorInTerminalText = function(text) {
            if (!text) return;
            
            const pyRegex = /File\s+"([^"]+)",\s+line\s+(\d+)/i;
            const jsRegex = /(?:at\s+.*\(|at\s+)([a-zA-Z]:\\[^:\n]+):(\d+)(?::(\d+))?/i;
            const cppRegex = /([a-zA-Z]:\\[^(\n]+)\((\d+)\)\s*:\s*(?:error|warning)/i;
            const gdRegex = /(res:\/\/[^:\n]+):(\d+)/i;

            let match = text.match(pyRegex);
            if (match) {
                window.highlightErrorInEditor(match[1], parseInt(match[2], 10), "Error de ejecución Python");
                if (typeof window.triggerCardinalIntervention === 'function') {
                    window.triggerCardinalIntervention(match[1], parseInt(match[2], 10), text, "Python");
                }
                return;
            }

            match = text.match(jsRegex);
            if (match) {
                window.highlightErrorInEditor(match[1], parseInt(match[2], 10), "Error de ejecución Node.js");
                if (typeof window.triggerCardinalIntervention === 'function') {
                    window.triggerCardinalIntervention(match[1], parseInt(match[2], 10), text, "Node.js");
                }
                return;
            }

            match = text.match(cppRegex);
            if (match) {
                window.highlightErrorInEditor(match[1], parseInt(match[2], 10), "Error de compilación C++");
                if (typeof window.triggerCardinalIntervention === 'function') {
                    window.triggerCardinalIntervention(match[1], parseInt(match[2], 10), text, "C++");
                }
                return;
            }
            
            match = text.match(gdRegex);
            if (match) {
                const resPath = match[1];
                const lineNum = parseInt(match[2], 10);
                const localPath = resPath.replace('res://', '').replace(/\//g, path.sep);
                const fullPath = path.resolve(workspaceRoot, localPath);
                window.highlightErrorInEditor(fullPath, lineNum, "Error de GDScript");
                if (typeof window.triggerCardinalIntervention === 'function') {
                    window.triggerCardinalIntervention(fullPath, lineNum, text, "GDScript");
                }
                return;
            }
        };

        window.createNewSkillPrompt = () => {
            window.openSkillEditorModal();
        };

        window.openSkillEditorModal = (skillId = '') => {
            let skill = {
                id: '',
                name: '',
                description: '',
                systemPrompt: '',
                commandTemplate: '',
                scriptCode: '',
                enabled: true
            };
            
            if (skillId) {
                const skills = window.getSkills();
                const found = skills.find(s => s.id === skillId);
                if (found) skill = found;
            }
            
            const isEdit = !!skillId;
            
            const htmlContent = `
                <div style="padding: 16px; color: #c9d1d9; background: #0d1117; font-family: 'Segoe UI', system-ui, sans-serif; height: calc(100% - 32px); display: flex; flex-direction: column; gap: 12px; overflow-y: auto;">
                    <h3 style="margin:0 0 5px 0; color:#fff; font-size: 16px;">${isEdit ? '📝 Editar Habilidad de IA' : '🪄 Crear Nueva Habilidad de IA'}</h3>
                    <p style="margin:0; font-size:11px; color:#8b949e;">Define cómo la IA debe activar esta habilidad y qué comandos o scripts debe ejecutar en tu sistema.</p>
                    
                    <div style="display:flex; gap:10px; margin-top:5px;">
                        <div style="flex:1; display:flex; flex-direction:column; gap:4px;">
                            <label style="font-size:11px; font-weight:bold; color:#a5d6ff;">ID de Habilidad (Único, minúsculas)</label>
                            <input type="text" id="skill-editor-id" value="${skill.id}" placeholder="ej. gen_imagen" ${isEdit ? 'disabled' : ''} style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:6px; color:#fff; font-size:12px; outline:none;">
                        </div>
                        <div style="flex:1; display:flex; flex-direction:column; gap:4px;">
                            <label style="font-size:11px; font-weight:bold; color:#a5d6ff;">Nombre de la Habilidad</label>
                            <input type="text" id="skill-editor-name" value="${skill.name}" placeholder="ej. Dibujar Imagen" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:6px; color:#fff; font-size:12px; outline:none;">
                        </div>
                    </div>
                    
                    <div style="display:flex; flex-direction:column; gap:4px;">
                        <label style="font-size:11px; font-weight:bold; color:#a5d6ff;">Descripción corta</label>
                        <input type="text" id="skill-editor-desc" value="${skill.description}" placeholder="Describe brevemente qué hace esta habilidad..." style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:6px; color:#fff; font-size:12px; outline:none;">
                    </div>
                    
                    <div style="display:flex; flex-direction:column; gap:4px;">
                        <label style="font-size:11px; font-weight:bold; color:#a5d6ff;">Instrucciones / System Prompt para la IA</label>
                        <textarea id="skill-editor-prompt" placeholder="Indica a la IA bajo qué condiciones usar el formato [SKILL: id_habilidad argumentos]. Ej:\nCuando el usuario te pida dibujar una imagen, responde con [SKILL: gen_imagen <descripción_detallada>]" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:8px; color:#fff; font-size:12px; outline:none; min-height:80px; resize:vertical; font-family:inherit;">${skill.systemPrompt}</textarea>
                    </div>

                    <div style="display:flex; flex-direction:column; gap:4px;">
                        <label style="font-size:11px; font-weight:bold; color:#a5d6ff;">Plantilla de Comando de Terminal (Opcional)</label>
                        <input type="text" id="skill-editor-cmd" value="${skill.commandTemplate}" placeholder="ej. python skills/gen_imagen.py {args}" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:6px; color:#fff; font-size:12px; outline:none; font-family:monospace;">
                        <span style="font-size:9px; color:#8b949e;">Nota: Use {args} para interpolar los argumentos de la IA en la línea de comando.</span>
                    </div>

                    <div style="display:flex; flex-direction:column; gap:4px; flex:1;">
                        <label style="font-size:11px; font-weight:bold; color:#a5d6ff;">Código de Script (Opcional - Python por defecto)</label>
                        <textarea id="skill-editor-script" placeholder="# Código del script que se guardará en skills/id_habilidad.py\nimport sys\narguments = sys.argv[1:]\nprint('Procesando argumentos:', arguments)" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:8px; color:#fff; font-size:11px; outline:none; flex:1; min-height:100px; font-family:monospace; resize:vertical;">${skill.scriptCode}</textarea>
                    </div>
                    
                    <div style="display:flex; justify-content:flex-end; gap:10px; margin-top:5px; border-top:1px solid #30363d; padding-top:10px;">
                        <button id="btn-cancel-skill" style="background:#21262d; border:1px solid #30363d; color:#c9d1d9; padding:6px 16px; border-radius:6px; cursor:pointer; font-family:inherit; font-size:12px;">Cancelar</button>
                        <button id="btn-save-skill" style="background:#7c3aed; color:#fff; border:none; padding:6px 16px; border-radius:6px; cursor:pointer; font-family:inherit; font-weight:bold; font-size:12px;">Guardar Habilidad</button>
                    </div>
                </div>
            `;
            
            const editorWin = new NexusWindow({
                id: 'nexus-win-skill-editor',
                title: isEdit ? "Editar Habilidad: " + skill.name : 'Nueva Habilidad de IA',
                icon: '🪄',
                width: 600,
                height: 520,
                content: htmlContent
            });
            
            document.getElementById('btn-cancel-skill').addEventListener('click', () => {
                document.getElementById('nexus-win-skill-editor')?.remove();
            });
            
            document.getElementById('btn-save-skill').addEventListener('click', () => {
                const idInput = document.getElementById('skill-editor-id');
                const nameInput = document.getElementById('skill-editor-name');
                const descInput = document.getElementById('skill-editor-desc');
                const promptInput = document.getElementById('skill-editor-prompt');
                const cmdInput = document.getElementById('skill-editor-cmd');
                const scriptInput = document.getElementById('skill-editor-script');
                
                const id = idInput.value.trim().toLowerCase().replace(/[^a-z0-9_]/g, '');
                const name = nameInput.value.trim();
                const description = descInput.value.trim();
                const systemPrompt = promptInput.value.trim();
                const commandTemplate = cmdInput.value.trim();
                const scriptCode = scriptInput.value.trim();
                
                if (!id || !name || !systemPrompt) {
                    showToast("Por favor rellene el ID, Nombre e Instrucciones de la Habilidad.", "warning");
                    return;
                }
                
                const newSkill = {
                    id,
                    name,
                    description,
                    systemPrompt,
                    commandTemplate,
                    scriptCode,
                    enabled: skill.enabled
                };
                
                window.saveSkill(newSkill);
                showToast("Habilidad guardada correctamente", "success");
                document.getElementById('nexus-win-skill-editor')?.remove();
                window.refreshSkillsUI();
                renderExplorer();
            });
        };

        window.getSkillsSystemPrompt = function() {
            if (typeof window.getSkills !== 'function') return '';
            const skills = window.getSkills().filter(s => s.enabled);
            if (skills.length === 0) return '';
            
            let prompt = '\n\n=== HABILIDADES DE IA ADICIONALES (AI SKILLS) ===\n';
            prompt += 'Tienes habilidades personalizadas instaladas por el usuario. Si necesitas usarlas para responder al usuario, responde INCLUYENDO EXACTAMENTE la etiqueta:\n';
            prompt += '[SKILL: <id_habilidad> <argumentos>]\n\n';
            prompt += 'Habilidades disponibles:\n';
            skills.forEach(s => {
                prompt += `- Habilidad ID: ${s.id}\n  Nombre: ${s.name}\n  Descripción: ${s.description}\n  Instrucciones de activación: ${s.systemPrompt}\n`;
                if (s.commandTemplate) {
                    prompt += `  Comando a ejecutar: ${s.commandTemplate}\n`;
                }
                prompt += '\n';
            });
            return prompt;
        };

        // ==========================================
        // SISTEMA DE PLUGINS & MARKETPLACE DE NEXUS
        // ==========================================

        const MARKETPLACE_PLUGINS = [
            { id: 'git-graph', name: '📊 Visual Git Graph', description: 'Visualiza de forma hermosa el árbol de ramas y commits del repositorio Git actual de tu espacio de trabajo.', author: 'Nexus Dev Team', version: '1.2.0', type: 'core' },
            { id: 'db-client', name: '🗄️ Database Client (SQLite)', description: 'Una interfaz gráfica premium e interactiva para explorar tablas y ejecutar queries SQL sobre bases de datos locales.', author: 'Nexus Dev Team', version: '1.0.5', type: 'core' },
            { id: 'asistente-personal', name: '🤖 Asistente Personal', description: 'Un compañero de IA personalizable para gestionar tus notas, tareas de desarrollo y comandos rápidos.', author: 'Nexus Dev Team', version: '1.0.0', type: 'core' },
            { id: 'excalidraw-board', name: '🎨 Excalidraw Sketchpad', description: 'Dibuja esquemas de arquitectura, diagramas de flujo y bocetos interactivos directamente en el IDE.', author: 'Community Labs', version: '2.1.0', type: 'iframe' },
            { id: 'regex-tester', name: '🔍 RegEx Sandbox & Tester', description: 'Prueba, valida y depura expresiones regulares en tiempo real con resaltado visual de coincidencias.', author: 'Regex Devs', version: '1.1.0', type: 'tool' },
            { id: 'spotify-mini', name: '🎵 Spotify Controller', description: 'Controla tu música favorita y reproduce/pausa pistas directamente desde la barra inferior de la aplicación.', author: 'Audio Integration', version: '1.0.0', type: 'widget' },
            { id: 'json-prettifier', name: '📦 JSON Formatter & Parser', description: 'Formatea, valida, minifica y visualiza la jerarquía de tus archivos JSON con un validador de errores integrado.', author: 'DevUtils Corp', version: '1.3.1', type: 'tool' },
            { id: 'visual-blueprints', name: '⚡ Visual Blueprints (Visual Scripting)', description: 'Diseña lógica de forma visual conectando nodos (inicio, condicionales, bucles, variables, archivos, APIs) y compila código fuente JavaScript limpio al instante.', author: 'Nexus Dev Team', version: '1.0.0', type: 'core' },
            { id: 'color-studio', name: '🎨 Color Studio', description: 'Selector de color visual con conversión instantánea entre HEX, RGB y HSL, vista previa y copiado al portapapeles.', author: 'Nexus Dev Team', version: '1.0.0', type: 'tool' },
            { id: 'encoder-decoder', name: '🔐 Encoder / Decoder', description: 'Codifica y decodifica texto en Base64 y URL, y decodifica tokens JWT mostrando su cabecera y payload.', author: 'Nexus Dev Team', version: '1.0.0', type: 'tool' },
            { id: 'hash-uuid', name: '#️⃣ Hash & UUID Generator', description: 'Genera hashes MD5, SHA-1 y SHA-256 de cualquier texto y crea identificadores únicos UUID v4 al instante.', author: 'Nexus Dev Team', version: '1.0.0', type: 'tool' },
            { id: 'timestamp-converter', name: '🕐 Timestamp Converter', description: 'Convierte marcas de tiempo Unix (segundos o milisegundos) a fechas legibles (local, UTC, ISO) y viceversa.', author: 'Nexus Dev Team', version: '1.0.0', type: 'tool' },
            { id: 'diff-checker', name: '🔀 Diff Checker', description: 'Compara dos bloques de texto línea a línea y resalta las diferencias (añadidos, eliminados e iguales).', author: 'Nexus Dev Team', version: '1.0.0', type: 'tool' }
        ];

        function getInstalledPlugins() {
            try {
                return JSON.parse(localStorage.getItem('nexus_installed_plugins') || '[]');
            } catch(e) {
                return [];
            }
        }

        function saveInstalledPlugins(list) {
            localStorage.setItem('nexus_installed_plugins', JSON.stringify(list));
        }

        function openPluginMarketplaceModal() {
            const installed = getInstalledPlugins();
            
            const htmlContent = `
                <div style="padding: 20px; color: #c9d1d9; background: #0d1117; font-family: 'Segoe UI', system-ui, sans-serif; display: flex; flex-direction: column; gap: 20px; height: calc(100% - 40px); overflow-y: auto;">
                    
                    <!-- Cabecera de la Galería -->
                    <div style="display: flex; align-items: center; justify-content: space-between; border-bottom: 1px solid #30363d; padding-bottom: 15px;">
                        <div>
                            <h2 style="margin: 0; font-size: 20px; color: #e6edf3; display: flex; align-items: center; gap: 10px;">🔌 Galería de Plugins / Marketplace</h2>
                            <p style="margin: 5px 0 0 0; font-size: 13px; color: #8b949e;">Instala utilidades premium o importa plugins externos de repositorios Git.</p>
                        </div>
                        <input type="text" id="mkt-search" placeholder="Buscar plugin..." style="background: #161b22; border: 1px solid #30363d; border-radius: 6px; color: #e6edf3; padding: 6px 12px; font-size: 12px; outline: none; width: 200px;">
                    </div>

                    <!-- Instalador desde URL de Git -->
                    <div style="background: rgba(124, 58, 237, 0.05); border: 1px solid rgba(124, 58, 237, 0.2); border-radius: 8px; padding: 15px; display: flex; flex-direction: column; gap: 10px;">
                        <h4 style="margin: 0; font-size: 13px; color: #a5d6ff; display: flex; align-items: center; gap: 8px;">📥 Instalar desde Repositorio Git Externo</h4>
                        <div style="display: flex; gap: 10px;">
                            <input type="text" id="git-plugin-url" placeholder="https://github.com/usuario/nexus-plugin.git" style="flex: 1; background: #161b22; border: 1px solid #30363d; border-radius: 6px; color: #e6edf3; padding: 8px 12px; font-size: 12px; outline: none;">
                            <button id="btn-git-install" onclick="window.installPluginFromGit()" class="dash-btn dash-primary-btn" style="padding: 8px 16px;">Clonar e Instalar</button>
                        </div>
                    </div>

                    <!-- Listado de Plugins -->
                    <div id="mkt-grid" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(320px, 1fr)); gap: 16px; margin-top: 10px;">
                        <!-- Se llena dinámicamente -->
                    </div>
                </div>
            `;

            const win = new NexusWindow({
                id: 'nexus-win-plugin-marketplace',
                title: 'Galería de Plugins & Marketplace',
                icon: '🔌',
                width: 780,
                height: 580,
                content: htmlContent
            });

            // Funciones reactivas asignadas a window
            window.installPluginFromGit = () => {
                const urlInput = document.getElementById('git-plugin-url');
                const gitUrl = urlInput.value.trim();
                if (!gitUrl) {
                    showToast("Por favor ingresa una URL válida de Git", "error");
                    return;
                }

                const repoName = gitUrl.split('/').pop().replace('.git', '');
                const targetDir = path.join(workspaceRoot, 'plugins', repoName);

                showToast(`Clonando e instalando plugin: ${repoName}...`, "info");
                const btn = document.getElementById('btn-git-install');
                btn.disabled = true;
                btn.textContent = "Clonando...";

                const { exec } = require('child_process');
                fs.mkdirSync(path.join(workspaceRoot, 'plugins'), { recursive: true });

                exec(`git clone "${gitUrl}" "${targetDir}"`, (error, stdout, stderr) => {
                    btn.disabled = false;
                    btn.textContent = "Clonar e Instalar";
                    
                    if (error) {
                        showToast(`Error de clonación: ${error.message}`, "error");
                        return;
                    }

                    // Guardar en la base de datos de plugins instalados
                    const installedList = getInstalledPlugins();
                    if (!installedList.includes(repoName)) {
                        installedList.push(repoName);
                        saveInstalledPlugins(installedList);
                    }

                    // Crear metadatos locales si no existen
                    const configPath = path.join(targetDir, 'plugin.json');
                    if (!fs.existsSync(configPath)) {
                        const defaultJson = {
                            id: repoName,
                            name: `🔌 ${repoName}`,
                            description: "Plugin externo importado mediante clonación de Git.",
                            author: "Externo",
                            version: "1.0.0"
                        };
                        fs.writeFileSync(configPath, JSON.stringify(defaultJson, null, 2), 'utf8');
                    }

                    showToast(`Plugin '${repoName}' instalado con éxito`, "success");
                    urlInput.value = '';
                    renderExplorer();
                    window.refreshMktGrid();
                });
            };

            window.toggleInstallPlugin = (pId) => {
                const installedList = getInstalledPlugins();
                const index = installedList.indexOf(pId);
                const isInstalling = index === -1;

                if (isInstalling) {
                    installedList.push(pId);
                    // Crear la estructura simulada en el explorador
                    try {
                        const targetDir = path.join(workspaceRoot, 'plugins', pId);
                        fs.mkdirSync(targetDir, { recursive: true });
                        const pluginMeta = MARKETPLACE_PLUGINS.find(m => m.id === pId);
                        fs.writeFileSync(
                            path.join(targetDir, 'plugin.json'),
                            JSON.stringify(pluginMeta, null, 4),
                            'utf8'
                        );
                        fs.writeFileSync(
                            path.join(targetDir, 'README.md'),
                            `# ${pluginMeta.name}\n\n${pluginMeta.description}\n\nInstalado el ${new Date().toLocaleDateString()}`,
                            'utf8'
                        );
                    } catch(e) {
                        console.error("Error al crear archivos del plugin en el espacio de trabajo:", e);
                    }
                    showToast(`Plugin '${pId}' instalado y activado con éxito.`, "success");
                } else {
                    installedList.splice(index, 1);
                    // Remover directorio de plugin opcionalmente
                    try {
                        const targetDir = path.join(workspaceRoot, 'plugins', pId);
                        if (fs.existsSync(targetDir)) {
                            fs.rmSync(targetDir, { recursive: true, force: true });
                        }
                    } catch(e) {
                        console.error(e);
                    }
                    showToast(`Plugin '${pId}' desinstalado.`, "info");
                }

                saveInstalledPlugins(installedList);
                renderExplorer();
                window.refreshMktGrid();
            };

            window.refreshMktGrid = () => {
                const searchVal = document.getElementById('mkt-search')?.value.toLowerCase() || '';
                const grid = document.getElementById('mkt-grid');
                if (!grid) return;

                grid.innerHTML = '';
                const currentInstalled = getInstalledPlugins();

                MARKETPLACE_PLUGINS.forEach(p => {
                    if (searchVal && !p.name.toLowerCase().includes(searchVal) && !p.description.toLowerCase().includes(searchVal)) {
                        return;
                    }

                    const isInst = currentInstalled.includes(p.id);
                    const btnClass = isInst ? 'dash-btn' : 'dash-btn dash-primary-btn';
                    const btnText = isInst ? '✓ Activo (Desinstalar)' : 'Instalar Plugin';
                    const card = document.createElement('div');
                    card.style.cssText = `
                        background: #161b22;
                        border: 1px solid #30363d;
                        border-radius: 8px;
                        padding: 16px;
                        display: flex;
                        flex-direction: column;
                        justify-content: space-between;
                        gap: 12px;
                        transition: transform 0.2s, border-color 0.2s;
                    `;
                    card.addEventListener('mouseenter', () => {
                        card.style.borderColor = '#7c3aed';
                    });
                    card.addEventListener('mouseleave', () => {
                        card.style.borderColor = '#30363d';
                    });

                    card.innerHTML = `
                        <div>
                            <div style="display: flex; align-items: center; justify-content: space-between;">
                                <h3 style="margin: 0; font-size: 15px; color: #f0f6fc;">${p.name}</h3>
                                <span style="font-size: 10px; background: rgba(255,255,255,0.06); padding: 2px 6px; border-radius: 10px; color: #8b949e;">v${p.version}</span>
                            </div>
                            <p style="margin: 8px 0 0 0; font-size: 11px; color: #8b949e; line-height: 1.4; height: 42px; overflow: hidden; text-overflow: ellipsis;">${p.description}</p>
                            <div style="margin-top: 10px; font-size: 10px; color: #6e7681;">Autor: <strong style="color: #c9d1d9;">${p.author}</strong></div>
                        </div>
                        <button onclick="window.toggleInstallPlugin('${p.id}')" class="${btnClass}" style="width: 100%; text-align: center; justify-content: center; font-size: 11px; padding: 6px;">${btnText}</button>
                    `;
                    grid.appendChild(card);
                });
            };

            // Bind de búsqueda
            document.getElementById('mkt-search').addEventListener('input', window.refreshMktGrid);
            window.refreshMktGrid();

            win.onClose = () => {
                delete window.installPluginFromGit;
                delete window.toggleInstallPlugin;
                delete window.refreshMktGrid;
            };
        }

        function showInstalledPluginsModal() {
            const installed = getInstalledPlugins();
            const content = document.createElement('div');
            content.style.cssText = `
                padding: 20px;
                color: #c9d1d9;
                background: #0d1117;
                font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
                height: 100%;
                overflow-y: auto;
            `;

            if (installed.length === 0) {
                content.innerHTML = `
                    <div style="text-align: center; padding: 40px 20px;">
                        <span style="font-size: 40px;">🔌</span>
                        <h3 style="margin-top: 10px;">No tienes plugins activos</h3>
                        <p style="color: #8b949e; font-size: 12px;">Visita la Galería de Plugins para instalar o importar utilidades.</p>
                        <button onclick="openPluginMarketplaceModal()" class="dash-btn dash-primary-btn" style="margin-top: 15px; display: inline-flex;">Ir a la Galería</button>
                    </div>
                `;
            } else {
                let html = `
                    <h2 style="margin: 0 0 15px 0; font-size: 18px; border-bottom: 1px solid #30363d; padding-bottom: 10px;">🔌 Plugins Instalados (${installed.length})</h2>
                    <div style="display: flex; flex-direction: column; gap: 10px;">
                `;

                installed.forEach(pId => {
                    const meta = MARKETPLACE_PLUGINS.find(m => m.id === pId) || { name: `🔌 ${pId}`, description: 'Plugin externo cargado desde Git.', author: 'Externo', version: '1.0.0' };
                    html += `
                        <div style="background: #161b22; border: 1px solid #30363d; border-radius: 6px; padding: 12px; display: flex; align-items: center; justify-content: space-between; gap: 15px;">
                            <div>
                                <h4 style="margin: 0; font-size: 13px; color: #f0f6fc;">${meta.name}</h4>
                                <p style="margin: 4px 0 0 0; font-size: 11px; color: #8b949e;">${meta.description}</p>
                            </div>
                            <button onclick="window.runPluginFromList('${pId}')" class="dash-btn dash-primary-btn" style="padding: 6px 12px; font-size: 11px; flex-shrink: 0;">Ejecutar</button>
                        </div>
                    `;
                });

                // Agregar sección de Asistente Personal Core
                html += `
                    <div style="margin-top: 20px; border-top: 1px solid #30363d; padding-top: 15px;">
                        <h3 style="margin: 0 0 10px 0; font-size: 13px; color: #a78bfa; display: flex; align-items: center; gap: 8px;">🤖 Asistente Personal Core</h3>
                        <div style="background: rgba(167, 139, 250, 0.05); border: 1px solid rgba(167, 139, 250, 0.2); border-radius: 6px; padding: 12px; display: flex; align-items: center; justify-content: space-between; gap: 15px;">
                            <div>
                                <h4 style="margin: 0; font-size: 13px; color: #f0f6fc;">🤖 Asistente Personal (AIRI)</h4>
                                <p style="margin: 4px 0 0 0; font-size: 11px; color: #8b949e;">Configura y abre tu copiloto personal de IA con voz, visión y auto-aprendizaje.</p>
                            </div>
                            <div style="display: flex; gap: 8px; flex-shrink: 0;">
                                <button onclick="window.runPluginFromList('asistente-personal')" class="dash-btn dash-primary-btn" style="padding: 6px 12px; font-size: 11px;">Ejecutar</button>
                                <button onclick="window.openAssistantConfigFromList()" class="dash-btn" style="padding: 6px 12px; font-size: 11px; border: 1px solid #30363d; background: #21262d; color: #c9d1d9;">Configurar</button>
                            </div>
                        </div>
                    </div>
                `;

                html += `</div>`;
                content.innerHTML = html;
            }

            const win = new NexusWindow({
                id: 'nexus-win-installed-plugins',
                title: 'Plugins Instalados',
                icon: '🔌',
                width: 500,
                height: 520,
                content: content.outerHTML
            });

            window.runPluginFromList = (pId) => {
                runPlugin(pId);
                win.close();
            };

            win.onClose = () => {
                delete window.runPluginFromList;
            };
        }

        function runPlugin(pluginId) {
            const installed = getInstalledPlugins();
            const alwaysAvailable = ['git-graph', 'db-client', 'excalidraw-board', 'visual-blueprints', 'asistente-personal', 'color-studio', 'encoder-decoder', 'hash-uuid', 'timestamp-converter', 'diff-checker'];
            if (!installed.includes(pluginId) && !alwaysAvailable.includes(pluginId)) {
                showToast("Este plugin no está instalado.", "error");
                return;
            }

            if (pluginId === 'git-graph') {
                openGitGraphPlugin();
            } else if (pluginId === 'db-client') {
                openDbClientPlugin();
            } else if (pluginId === 'excalidraw-board') {
                openExcalidrawPlugin();
            } else if (pluginId === 'regex-tester') {
                openRegexTesterPlugin();
            } else if (pluginId === 'spotify-mini') {
                openSpotifyPlugin();
            } else if (pluginId === 'json-prettifier') {
                openJsonPrettifierPlugin();
            } else if (pluginId === 'visual-blueprints') {
                openVisualBlueprintsPlugin();
            } else if (pluginId === 'asistente-personal') {
                openPersonalAssistantPlugin();
            } else if (pluginId === 'color-studio') {
                openColorStudioPlugin();
            } else if (pluginId === 'encoder-decoder') {
                openEncoderDecoderPlugin();
            } else if (pluginId === 'hash-uuid') {
                openHashUuidPlugin();
            } else if (pluginId === 'timestamp-converter') {
                openTimestampConverterPlugin();
            } else if (pluginId === 'diff-checker') {
                openDiffCheckerPlugin();
            } else {
                openGenericPluginWindow(pluginId);
            }
        }

        // NOTA: plugins de utilidad movidos a modules/plugins-utils.js (Color/Encoder/Hash-UUID/Timestamp/Diff)

        // 1. PLUGIN: VISUAL GIT GRAPH
        function openGitGraphPlugin() {
            const { exec } = require('child_process');
            
            const htmlContent = `
                <div style="padding: 16px; color: #c9d1d9; background: #0d1117; font-family: monospace; height: calc(100% - 32px); display: flex; flex-direction: column; gap: 10px;">
                    <div style="display:flex; justify-content:space-between; align-items:center; border-bottom:1px solid #30363d; padding-bottom:10px;">
                        <span style="font-size:13px; font-weight:bold; color:#a5d6ff;">📊 Historial Git Visualizado</span>
                        <button onclick="window.refreshGitGraph()" class="dash-btn" style="padding: 4px 8px; font-size:10px;">Actualizar</button>
                    </div>
                    <div id="git-graph-console" style="flex:1; overflow:auto; background:#161b22; border:1px solid #30363d; border-radius:6px; padding:12px; font-size:11px; white-space:pre; line-height:1.5; color:#e6edf3;">
                        Cargando grafo de Git...
                    </div>
                </div>
            `;

            const win = new NexusWindow({
                id: 'nexus-win-git-graph-plugin',
                title: 'Visual Git Graph',
                icon: '📊',
                width: 700,
                height: 480,
                content: htmlContent
            });

            window.refreshGitGraph = () => {
                const container = document.getElementById('git-graph-console');
                if (!container) return;

                exec('git log --graph --oneline --decorate --all -n 35', { cwd: workspaceRoot }, (error, stdout, stderr) => {
                    if (error) {
                        container.innerHTML = `<span style="color:#ff7b72;">⚠️ Error al leer Git: ${error.message}</span>\n\nAsegúrate de estar en un repositorio Git activo.`;
                        return;
                    }

                    // Colorear el grafo
                    let formatted = stdout
                        .replace(/&/g, "&amp;")
                        .replace(/</g, "&lt;")
                        .replace(/>/g, "&gt;");

                    // Resaltar commits hashes
                    formatted = formatted.replace(/^([*|\s/\\]+)([a-f0-9]{7})/gm, '$1<span style="color:#58a6ff; font-weight:bold;">$2</span>');
                    // Resaltar decoraciones de rama (HEAD -> main, etc)
                    formatted = formatted.replace(/(\((tag: )?[^)]+\))/g, '<span style="color:#56d364; font-weight:bold;">$1</span>');
                    // Colorear ramas del árbol gráfico
                    formatted = formatted.replace(/([*|/\\_.-]+)/g, '<span style="color:#ff7b72;">$1</span>');

                    container.innerHTML = formatted || 'Repositorio vacío sin commits aún.';
                });
            };

            window.refreshGitGraph();
            win.onClose = () => {
                delete window.refreshGitGraph;
            };
        }

        // 2. PLUGIN: DATABASE CLIENT (SQLite)
        function openDbClientPlugin() {
            const htmlContent = `
                <div style="padding: 16px; color: #c9d1d9; background: #0d1117; font-family: 'Segoe UI', sans-serif; height: calc(100% - 32px); display: flex; flex-direction: column; gap: 12px;">
                    <div style="display: flex; flex-direction: column; gap: 8px; border-bottom: 1px solid #30363d; padding-bottom: 12px;">
                        <div style="display: flex; gap: 10px; align-items: center; flex-wrap: wrap;">
                            <div style="display:flex; flex-direction:column; width:130px;">
                                <span style="font-size:10px; color:#8b949e; margin-bottom: 4px;">Motor de Base de Datos</span>
                                <select id="db-engine-select" onchange="window.toggleDbEngineUI()" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:4px; color:#fff; font-size:12px; outline:none; height:28px;">
                                    <option value="sqlite">SQLite (Archivo)</option>
                                    <option value="mssql">SQL Server / Azure SQL</option>
                                    <option value="mysql">MySQL</option>
                                    <option value="postgres">PostgreSQL</option>
                                </select>
                            </div>
                            
                            <div id="db-local-path-container" style="display:flex; flex-direction:column; flex:1; min-width: 200px;">
                                <span style="font-size:10px; color:#8b949e; margin-bottom: 4px;">Ruta base de datos SQLite</span>
                                <input type="text" id="db-path-input" value="db.sqlite" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:4px 8px; color:#e6edf3; font-size:12px; outline:none; height:18px;">
                            </div>
                            
                            <div id="db-remote-conn-container" style="display:none; gap:8px; flex:1; flex-wrap:wrap; min-width: 300px;">
                                <div style="display:flex; flex-direction:column; flex:2; min-width: 120px;">
                                    <span style="font-size:10px; color:#8b949e; margin-bottom: 4px;">Servidor / Host</span>
                                    <input type="text" id="db-host-input" placeholder="ej. localhost o sql.database.windows.net" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:4px 8px; color:#fff; font-size:12px; outline:none; height:18px;">
                                </div>
                                <div style="display:flex; flex-direction:column; width:50px;">
                                    <span style="font-size:10px; color:#8b949e; margin-bottom: 4px;">Puerto</span>
                                    <input type="text" id="db-port-input" placeholder="1433" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:4px 8px; color:#fff; font-size:12px; outline:none; height:18px;">
                                </div>
                                <div style="display:flex; flex-direction:column; flex:1; min-width: 80px;">
                                    <span style="font-size:10px; color:#8b949e; margin-bottom: 4px;">Base de Datos</span>
                                    <input type="text" id="db-name-input" placeholder="db_name" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:4px 8px; color:#fff; font-size:12px; outline:none; height:18px;">
                                </div>
                                <div style="display:flex; flex-direction:column; flex:1; min-width: 80px;">
                                    <span style="font-size:10px; color:#8b949e; margin-bottom: 4px;">Usuario</span>
                                    <input type="text" id="db-user-input" placeholder="sa" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:4px 8px; color:#fff; font-size:12px; outline:none; height:18px;">
                                </div>
                                <div style="display:flex; flex-direction:column; flex:1; min-width: 80px;">
                                    <span style="font-size:10px; color:#8b949e; margin-bottom: 4px;">Contraseña</span>
                                    <input type="password" id="db-pass-input" placeholder="••••••••" style="background:#161b22; border:1px solid #30363d; border-radius:4px; padding:4px 8px; color:#fff; font-size:12px; outline:none; height:18px;">
                                </div>
                            </div>
                            
                            <button onclick="window.runSqlDbQuery()" class="dash-btn dash-primary-btn" style="padding: 6px 14px; margin-top:14px; font-size:11px; height: 28px;">Ejecutar SQL</button>
                        </div>
                    </div>
                    
                    <div style="display: flex; flex-direction: column; gap: 6px; height: 110px;">
                        <span style="font-size: 11px; font-weight: bold; color: #8b949e;">Consulta SQL</span>
                        <textarea id="db-sql-query" style="flex:1; background:#161b22; border:1px solid #30363d; border-radius:6px; color:#e6edf3; font-family:monospace; font-size:12px; padding:8px; outline:none; resize:none;">SELECT name FROM sqlite_master WHERE type='table';</textarea>
                    </div>
                    <div style="display: flex; flex-direction: column; flex: 1; min-height:0; gap: 6px;">
                        <span style="font-size: 11px; font-weight: bold; color: #8b949e;">Resultado de la Consulta</span>
                        <div id="db-result-container" style="flex:1; overflow:auto; background:#010409; border:1px solid #30363d; border-radius:6px; padding:8px;">
                            <span style="font-size:11px; color:#6e7681;">Configura la conexión, escribe una consulta y haz clic en Ejecutar SQL.</span>
                        </div>
                    </div>
                </div>
            `;

            const win = new NexusWindow({
                id: 'nexus-win-db-client-plugin',
                title: 'Database Client (Universal SQL Server & SQLite)',
                icon: '🗄️',
                width: 760,
                height: 520,
                content: htmlContent
            });

            window.toggleDbEngineUI = () => {
                const engine = document.getElementById('db-engine-select').value;
                const localContainer = document.getElementById('db-local-path-container');
                const remoteContainer = document.getElementById('db-remote-conn-container');
                const queryTextarea = document.getElementById('db-sql-query');
                const portInput = document.getElementById('db-port-input');

                if (engine === 'sqlite') {
                    localContainer.style.display = 'flex';
                    remoteContainer.style.display = 'none';
                    if (queryTextarea.value.trim().startsWith('SELECT') && queryTextarea.value.includes('sqlite_master')) {
                        // Keep as is
                    } else {
                        queryTextarea.value = "SELECT name FROM sqlite_master WHERE type='table';";
                    }
                } else {
                    localContainer.style.display = 'none';
                    remoteContainer.style.display = 'flex';
                    
                    if (engine === 'mssql') {
                        portInput.value = '1433';
                        queryTextarea.value = "SELECT TABLE_NAME FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_TYPE = 'BASE TABLE';";
                    } else if (engine === 'mysql') {
                        portInput.value = '3306';
                        queryTextarea.value = "SHOW TABLES;";
                    } else if (engine === 'postgres') {
                        portInput.value = '5432';
                        queryTextarea.value = "SELECT table_name FROM information_schema.tables WHERE table_schema='public';";
                    }
                }
            };

            window.runSqlDbQuery = () => {
                const engine = document.getElementById('db-engine-select').value;
                const sql = document.getElementById('db-sql-query').value.trim();
                const resultBox = document.getElementById('db-result-container');
                if (!sql) return;

                resultBox.innerHTML = '<span style="color:#facc15; font-size:11px; font-weight:bold;">⚡ Preparando entorno y ejecutando consulta...</span>';

                const config = {
                    engine: engine,
                    sql: sql
                };

                if (engine === 'sqlite') {
                    const dbPath = document.getElementById('db-path-input').value.trim();
                    if (!dbPath) {
                        resultBox.innerHTML = '<span style="color:#ff7b72; font-size:11px;">⚠️ Error: Especifica la ruta del archivo SQLite.</span>';
                        return;
                    }
                    config.db_path = path.isAbsolute(dbPath) ? dbPath : path.resolve(workspaceRoot, dbPath);
                } else {
                    config.host = document.getElementById('db-host-input').value.trim();
                    config.port = document.getElementById('db-port-input').value.trim();
                    config.database = document.getElementById('db-name-input').value.trim();
                    config.user = document.getElementById('db-user-input').value.trim();
                    config.password = document.getElementById('db-pass-input').value.trim();

                    if (!config.host || !config.database || !config.user) {
                        resultBox.innerHTML = '<span style="color:#ff7b72; font-size:11px;">⚠️ Error: Host, Base de datos y Usuario son obligatorios para motores remotos.</span>';
                        return;
                    }
                }

                const fs = require('fs');
                const os = require('os');
                const { exec } = require('child_process');
                
                const tempRunnerPath = path.join(os.tmpdir(), `nexus_db_runner_${Date.now()}.py`);
                
                const pythonCode = `
import sys
import json

def install_package(package_name):
    try:
        __import__(package_name)
    except ImportError:
        import subprocess
        try:
            subprocess.check_call([sys.executable, "-m", "pip", "install", package_name, "--quiet"])
        except Exception as e:
            print(json.dumps({"success": False, "error": f"Falta driver '{package_name}'. Autoinstalacion fallida: " + str(e)}))
            sys.exit(1)

def run():
    try:
        config = json.loads(sys.stdin.read())
    except Exception as e:
        print(json.dumps({"success": False, "error": "Error leyendo config stdin: " + str(e)}))
        return

    engine = config.get("engine")
    sql = config.get("sql")

    if engine == "sqlite":
        import sqlite3
        try:
            conn = sqlite3.connect(config.get("db_path"))
            c = conn.cursor()
            c.execute(sql)
            cols = [d[0] for d in c.description] if c.description else []
            rows = c.fetchall()
            print(json.dumps({"success": True, "cols": cols, "rows": rows}))
            conn.commit()
            conn.close()
        except Exception as e:
            print(json.dumps({"success": False, "error": str(e)}))

    elif engine == "mssql":
        install_package("pymssql")
        import pymssql
        try:
            conn = pymssql.connect(
                server=config.get("host"),
                port=int(config.get("port") or 1433),
                user=config.get("user"),
                password=config.get("password"),
                database=config.get("database"),
                timeout=15,
                login_timeout=15
            )
            c = conn.cursor()
            c.execute(sql)
            cols = [d[0] for d in c.description] if c.description else []
            rows = c.fetchall()
            formatted_rows = []
            for row in rows:
                new_row = []
                for val in row:
                    if hasattr(val, "isoformat"):
                        new_row.append(val.isoformat())
                    elif hasattr(val, "to_eng_string"):
                        new_row.append(str(val))
                    elif isinstance(val, (bytes, bytearray)):
                        new_row.append(val.hex())
                    else:
                        new_row.append(val)
                formatted_rows.append(new_row)
            print(json.dumps({"success": True, "cols": cols, "rows": formatted_rows}))
            conn.commit()
            conn.close()
        except Exception as e:
            print(json.dumps({"success": False, "error": str(e)}))

    elif engine == "mysql":
        install_package("pymysql")
        import pymysql
        try:
            conn = pymysql.connect(
                host=config.get("host"),
                port=int(config.get("port") or 3306),
                user=config.get("user"),
                password=config.get("password"),
                database=config.get("database"),
                charset='utf8mb4',
                connect_timeout=15
            )
            c = conn.cursor()
            c.execute(sql)
            cols = [d[0] for d in c.description] if c.description else []
            rows = c.fetchall()
            formatted_rows = []
            for row in rows:
                new_row = []
                for val in row:
                    if hasattr(val, "isoformat"):
                        new_row.append(val.isoformat())
                    elif isinstance(val, (bytes, bytearray)):
                        new_row.append(val.hex())
                    else:
                        new_row.append(val)
                formatted_rows.append(new_row)
            print(json.dumps({"success": True, "cols": cols, "rows": formatted_rows}))
            conn.commit()
            conn.close()
        except Exception as e:
            print(json.dumps({"success": False, "error": str(e)}))

    elif engine == "postgres":
        install_package("pg8000")
        import pg8000
        try:
            conn = pg8000.connect(
                host=config.get("host"),
                port=int(config.get("port") or 5432),
                user=config.get("user"),
                password=config.get("password"),
                database=config.get("database"),
                timeout=15
            )
            c = conn.cursor()
            c.execute(sql)
            cols = [d[0] for d in c.description] if c.description else []
            rows = c.fetchall()
            formatted_rows = []
            for row in rows:
                new_row = []
                for val in row:
                    if hasattr(val, "isoformat"):
                        new_row.append(val.isoformat())
                    elif isinstance(val, (bytes, bytearray)):
                        new_row.append(val.hex())
                    else:
                        new_row.append(val)
                formatted_rows.append(new_row)
            print(json.dumps({"success": True, "cols": cols, "rows": formatted_rows}))
            conn.commit()
            conn.close()
        except Exception as e:
            print(json.dumps({"success": False, "error": str(e)}))

if __name__ == "__main__":
    run()
`;

                try {
                    fs.writeFileSync(tempRunnerPath, pythonCode, 'utf-8');
                } catch(e) {
                    resultBox.innerHTML = `<span style="color:#ff7b72; font-size:11px;">⚠️ Error escribiendo runner: ${e.message}</span>`;
                    return;
                }

                const child = exec(`python "${tempRunnerPath}"`, (error, stdout, stderr) => {
                    try { fs.unlinkSync(tempRunnerPath); } catch(ex) {}

                    if (error) {
                        resultBox.innerHTML = `<span style="color:#ff7b72; font-size:11px;">⚠️ Error de Sistema: ${error.message}</span><br><pre style="font-size:10px; color:#8b949e; margin-top:5px;">${stderr}</pre>`;
                        return;
                    }

                    try {
                        const res = JSON.parse(stdout.trim());
                        if (!res.success) {
                            resultBox.innerHTML = `<span style="color:#ff7b72; font-size:11px;">⚠️ Error SQL / Conexión: ${res.error}</span>`;
                            return;
                        }

                        if (res.cols.length === 0) {
                            resultBox.innerHTML = `<span style="color:#56d364; font-size:11px; font-weight:bold;">✓ Consulta ejecutada con éxito. Filas afectadas: ${res.rows ? res.rows.length : 0}</span>`;
                            return;
                        }

                        let tableHtml = `
                            <div style="font-size:10px; color:#8b949e; margin-bottom:6px;">Resultados: ${res.rows.length} registros encontrados</div>
                            <table style="width:100%; border-collapse:collapse; font-size:11px; text-align:left; color:#c9d1d9;">
                                <thead>
                                    <tr style="border-bottom:2px solid #30363d; background:#161b22;">
                        `;
                        res.cols.forEach(col => {
                            tableHtml += `<th style="padding:6px; border:1px solid #30363d; color:#e6edf3;">${col}</th>`;
                        });
                        tableHtml += `</tr></thead><tbody>`;

                        res.rows.forEach((row, rIdx) => {
                            const bg = rIdx % 2 === 0 ? 'transparent' : 'rgba(255,255,255,0.01)';
                            tableHtml += `<tr style="border-bottom:1px solid #21262d; background:${bg};">`;
                            row.forEach(val => {
                                tableHtml += `<td style="padding:6px; border:1px solid #30363d;">${val === null ? '<span style="color:#8b949e;font-style:italic;">null</span>' : val}</td>`;
                            });
                            tableHtml += `</tr>`;
                        });

                        tableHtml += `</tbody></table>`;
                        resultBox.innerHTML = tableHtml;

                    } catch(err) {
                        resultBox.innerHTML = `<span style="color:#ff7b72; font-size:11px;">⚠️ Error al analizar salida JSON del runner: ${err.message}</span><br><pre style="font-size:10px; color:#8b949e; margin-top:5px;">${stdout}</pre>`;
                    }
                });

                child.stdin.write(JSON.stringify(config));
                child.stdin.end();
            };

            win.onClose = () => {
                delete window.toggleDbEngineUI;
                delete window.runSqlDbQuery;
            };
        }

        // 3. PLUGIN: EXCALIDRAW SKETCHPAD
