        let assistantChatHistory = [];

        function getAssistantConfig() {
            try {
                const defaults = {
                    apiProviderChat: 'google',
                    apiProviderComplex: 'anthropic',
                    apiProviderTokens: 'google',
                    voiceName: '',
                    customVoicePath: '',
                    interactionType: 'hybrid',
                    displayMode: 'window',
                    customAvatarPath: '',
                    avatarSize: 340,
                    skillVision: true,
                    skillSpotify: true,
                    skillEnvControl: false,
                    skillFiles: true,
                    skillMemory: true,
                    skillWebcam: false,
                    skillRemote: false,
                    skillAutoDev: true,
                    telegramToken: '',
                    discordToken: '',
                    discordChannelId: ''
                };
                const stored = JSON.parse(localStorage.getItem('nexus_assistant_config') || '{}');
                let config = { ...defaults, ...stored };
                if (stored.apiProvider && !stored.apiProviderChat) {
                    config.apiProviderChat = stored.apiProvider;
                }
                return config;
            } catch(e) {
                return {};
            }
        }

