        async function processAssistantInput(text) {
            const cfg = getAssistantConfig();
            
            // Render user message in UI
            appendAssistantMessage('user', text);

            // Dynamically select model based on task complexity
            let provider = cfg.apiProviderChat;
            
            const isComplex = cfg.skillVision && (text.toLowerCase().includes('pantalla') || text.toLowerCase().includes('ver') || text.toLowerCase().includes('captura') || text.toLowerCase().includes('screen') || text.toLowerCase().includes('mira') || text.toLowerCase().includes('cámara') || text.toLowerCase().includes('cam') || text.toLowerCase().includes('foto') || text.toLowerCase().includes('archivo') || text.toLowerCase().includes('carpeta') || text.toLowerCase().includes('plugin'));
            const isTokenIntensive = text.toLowerCase().includes('indexar') || text.toLowerCase().includes('rag') || text.toLowerCase().includes('buscar en proyecto') || text.toLowerCase().includes('leer todo') || assistantChatHistory.length > 10;

            if (isComplex) {
                provider = cfg.apiProviderComplex;
            } else if (isTokenIntensive) {
                provider = cfg.apiProviderTokens;
            }

            const modelId = getModelForProvider(provider);
            
            // Build system prompt based on skills
            let sysPrompt = "Eres AIRI, el Asistente Personal integrado de Nexus IDE. Eres atenta, profesional y de respuestas concisas. ";
            if (cfg.skillVision) {
                sysPrompt += "Tienes acceso a ver la pantalla del usuario si te pide revisar su pantalla (mediante capturas automáticas). ";
            }
            if (cfg.skillSpotify) {
                sysPrompt += "Puedes controlar la reproducción de música de Spotify. Si el usuario te pide reproducir, pausar, ir a la siguiente canción o la anterior, puedes incluir en tu respuesta la acción en el formato exacto: `[SPOTIFY:play]`, `[SPOTIFY:pause]`, `[SPOTIFY:next]`, o `[SPOTIFY:prev]`. ";
            }
            if (cfg.skillEnvControl) {
                sysPrompt += "Tienes control del entorno del PC. Si el usuario te pide APAGAR el PC, debes despedirte y agregar el comando en tu respuesta en el formato exacto: `[SYSTEM:shutdown]`. ";
            }
            if (cfg.skillFiles) {
                sysPrompt += "Tienes permiso para organizar y manipular archivos locales. ";
            }
            if (cfg.skillMemory) {
                sysPrompt += "Tienes un sistema de memoria y aprendizaje autónomo de errores. Si creas alarmas o recordatorios, contesta con `[REMINDER:minutes:text]`. ";
            }
            if (cfg.skillWebcam) {
                sysPrompt += "Puedes ver por la cámara web si el usuario lo solicita explícitamente agregando en tu respuesta: `[WEBCAM:capture]`. ";
            }
            if (cfg.skillAutoDev) {
                sysPrompt += "Puedes autoprogramarte nuevas habilidades solicitándolo internamente en el IDE. ";
            }

            // Capture screen if vision is active and prompt asks for it
            let imgAttachments = [];
            if (cfg.skillVision && (text.toLowerCase().includes('pantalla') || text.toLowerCase().includes('ver') || text.toLowerCase().includes('captura') || text.toLowerCase().includes('screen') || text.toLowerCase().includes('mira'))) {
                showToast("Capturando pantalla para análisis visual...", "info");
                const dataUrl = await captureScreen();
                if (dataUrl) {
                    const base64Data = dataUrl.split(',')[1];
                    imgAttachments.push({
                        name: 'screenshot.png',
                        type: 'image/png',
                        base64: base64Data
                    });
                }
            }

            // Show thinking status in assistant log/bubble
            appendAssistantMessage('assistant', 'Pensando...', true);

            try {
                // Prepare history format
                const apiHistory = assistantChatHistory.slice(0, -1)
                    .filter(h => !h.isLoading)
                    .map(h => ({
                        role: h.role === 'user' ? 'user' : 'assistant',
                        content: h.content
                    }));

                const response = await sendRequestToAI(modelId, text, sysPrompt, apiHistory, null, imgAttachments);
                
                // Remove loading message
                removeAssistantLoadingMessage();

                // Append and speak response
                appendAssistantMessage('assistant', response);
                speakText(response);

                // Handle Spotify Commands
                if (cfg.skillSpotify) {
                    if (response.includes('[SPOTIFY:play]') || response.includes('[SPOTIFY:toggle]')) {
                        controlSpotify('play');
                    } else if (response.includes('[SPOTIFY:pause]')) {
                        controlSpotify('pause');
                    } else if (response.includes('[SPOTIFY:next]')) {
                        controlSpotify('next');
                    } else if (response.includes('[SPOTIFY:prev]')) {
                        controlSpotify('prev');
                    }
                }

                // Handle Shutdown Command
                if (cfg.skillEnvControl && response.includes('[SYSTEM:shutdown]')) {
                    showToast("⚠️ Apagando el sistema en 5 segundos...", "warning");
                    setTimeout(() => {
                        shutdownPC();
                    }, 5000);
                }

                // Handle Reminder Command
                if (cfg.skillMemory && response.includes('[REMINDER:')) {
                    const match = response.match(/\[REMINDER:(\d+):([^\]]+)\]/);
                    if (match) {
                        const mins = parseInt(match[1], 10);
                        const remText = match[2];
                        addReminder(remText, mins);
                    }
                }

                // Handle Webcam Command
                if (cfg.skillWebcam && response.includes('[WEBCAM:capture]')) {
                    showToast("Activando cámara web...", "info");
                    const imgData = await captureWebcam();
                    if (imgData) {
                        appendAssistantMessage('user', '[Imagen de Cámara Web capturada]');
                        // Re-query assistant with the webcam picture
                        const webcamBase64 = imgData.split(',')[1];
                        appendAssistantMessage('assistant', 'Analizando captura de cámara web...', true);
                        const webcamResponse = await sendRequestToAI(modelId, "Aquí está la captura de mi cámara web. ¿Qué observas?", sysPrompt, [], null, [{
                            name: 'webcam.jpg',
                            type: 'image/jpeg',
                            base64: webcamBase64
                        }]);
                        removeAssistantLoadingMessage();
                        appendAssistantMessage('assistant', webcamResponse);
                        speakText(webcamResponse);
                    }
                }

            } catch (err) {
                removeAssistantLoadingMessage();
                appendAssistantMessage('assistant', 'Lo siento, ocurrió un error al procesar tu solicitud: ' + err.message);
                showToast("Error del Asistente: " + err.message, "error");
            }
        }

        function appendAssistantMessage(role, content, isLoading = false) {
            assistantChatHistory.push({ role, content, isLoading });
            if (assistantChatHistory.length > 20) {
                assistantChatHistory = assistantChatHistory.slice(-20);
            }
            renderAssistantChatLog();
        }

        function removeAssistantLoadingMessage() {
            assistantChatHistory = assistantChatHistory.filter(h => !h.isLoading);
            renderAssistantChatLog();
        }

        function renderAssistantChatLog() {
            // Update VTuber bubble if active
            const bubble = document.getElementById('nexus-vtuber-bubble');
            if (bubble) {
                const lastMsg = assistantChatHistory[assistantChatHistory.length - 1];
                if (lastMsg && lastMsg.role === 'assistant') {
                    bubble.style.display = 'block';
                    bubble.textContent = lastMsg.content;
                }
            }

            // Update open personal assistant window log if it exists
            const logEl = document.getElementById('assistant-chat-log');
            if (!logEl) return;

            logEl.innerHTML = assistantChatHistory.map(m => {
                const isUser = m.role === 'user';
                const bg = isUser ? 'rgba(124, 58, 237, 0.15)' : 'rgba(255, 255, 255, 0.05)';
                const border = isUser ? 'rgba(124, 58, 237, 0.3)' : 'rgba(255, 255, 255, 0.1)';
                const align = isUser ? 'flex-end' : 'flex-start';
                const color = isUser ? '#fff' : '#e6edf3';
                const label = isUser ? 'Tú' : 'AIRI';

                return `
                    <div style="align-self: ${align}; background: ${bg}; border: 1px solid ${border}; border-radius: 8px; padding: 8px 12px; max-width: 80%; font-size: 11px; color: ${color}; line-height: 1.4; display: flex; flex-direction: column; gap: 4px; margin-bottom: 8px;">
                        <span style="font-size: 9px; color: #8b949e; font-weight: bold;">${label}</span>
                        <div>${m.content}</div>
                    </div>
                `;
            }).join('');
            logEl.scrollTop = logEl.scrollHeight;
        }

        function speakText(text) {
            const cfg = getAssistantConfig();
            if (cfg.interactionType === 'chat') return; // Chat only, no voice

            if ('speechSynthesis' in window) {
                // Cancel ongoing speech
                window.speechSynthesis.cancel();

                // Strip markdown format for TTS
                const cleanText = text.replace(/\[[^\]]+\]/g, '').replace(/[\*\_]/g, '');
                const utterance = new SpeechSynthesisUtterance(cleanText);
                
                // Select custom voice if configured
                if (cfg.voiceName) {
                    const voices = window.speechSynthesis.getVoices();
                    const chosen = voices.find(v => v.name === cfg.voiceName);
                    if (chosen) utterance.voice = chosen;
                }

                utterance.onstart = () => {
                    window.nexusAssistantIsSpeaking = true;
                    // Show bubble content on VTuber
                    const bubble = document.getElementById('nexus-vtuber-bubble');
                    if (bubble) {
                        bubble.style.display = 'block';
                        bubble.textContent = cleanText;
                    }
                };

                utterance.onend = () => {
                    window.nexusAssistantIsSpeaking = false;
                    // Auto-hide bubble after a brief timeout
                    setTimeout(() => {
                        const bubble = document.getElementById('nexus-vtuber-bubble');
                        if (bubble && !window.nexusAssistantIsSpeaking) {
                            bubble.style.display = 'none';
                        }
                    }, 4000);
                };

                window.speechSynthesis.speak(utterance);
            }
        }

        // NOTA: companion/avatar (nexusAvatarKind, startCompanionModel, toggleAssistantVTuber, refresco en caliente) movido a modules/companion.js

        async function captureScreen() {
            try {
                const { desktopCapturer } = require('electron');
                const sources = await desktopCapturer.getSources({ types: ['screen'], thumbnailSize: { width: 1280, height: 720 } });
                if (sources.length > 0) {
                    return sources[0].thumbnail.toDataURL();
                }
            } catch (e) {
                console.error("Screen capture failed:", e);
            }
            return null;
        }

        async function captureWebcam() {
            try {
                const video = document.createElement('video');
                const stream = await navigator.mediaDevices.getUserMedia({ video: true });
                video.srcObject = stream;
                await video.play();

                const canvas = document.createElement('canvas');
                canvas.width = 640;
                canvas.height = 480;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(video, 0, 0, 640, 480);
                
                stream.getTracks().forEach(track => track.stop());
                return canvas.toDataURL('image/jpeg');
            } catch(e) {
                console.error("Webcam capture failed:", e);
                showToast("No se pudo acceder a la cámara web: " + e.message, "error");
            }
            return null;
        }

        function controlSpotify(action) {
            if (action === 'play' || action === 'pause' || action === 'toggle') {
                if (typeof window.playPauseSpotify === 'function') window.playPauseSpotify();
                else showToast("Spotify no iniciado. Abre el plugin Spotify primero.", "warning");
            } else if (action === 'next') {
                if (typeof window.nextSpotify === 'function') window.nextSpotify();
                else showToast("Spotify no iniciado. Abre el plugin Spotify primero.", "warning");
            } else if (action === 'prev') {
                if (typeof window.prevSpotify === 'function') window.prevSpotify();
                else showToast("Spotify no iniciado. Abre el plugin Spotify primero.", "warning");
            }
        }

        function shutdownPC() {
            const { exec } = require('child_process');
            const platform = process.platform;
            if (platform === 'win32') {
                exec('shutdown /s /t 0');
            } else if (platform === 'darwin') {
                exec('osascript -e \'tell app "System Events" to shut down\'');
            } else {
                // Linux (Fedora, Arch, Debian, etc.): systemd primero, con fallbacks.
                exec('systemctl poweroff', (err) => {
                    if (err) exec('shutdown -h now', (err2) => {
                        if (err2) exec('poweroff');
                    });
                });
            }
        }

        const memoryFile = path.join(require('os').homedir(), '.nexus_assistant_memory.json');
        function getAssistantMemory() {
            try {
                if (fs.existsSync(memoryFile)) {
                    return JSON.parse(fs.readFileSync(memoryFile, 'utf8'));
                }
            } catch(e) {
                console.error("Error reading memory file:", e);
            }
            return { errorsSolved: [], reminders: [], generalNotes: "" };
        }

        function saveAssistantMemory(memory) {
            try {
                fs.writeFileSync(memoryFile, JSON.stringify(memory, null, 4), 'utf8');
            } catch(e) {
                console.error("Error writing memory file:", e);
            }
        }

        function addReminder(text, timeInMinutes) {
            const timeMs = timeInMinutes * 60 * 1000;
            setTimeout(() => {
                try {
                    new Notification("Asistente Personal: Recordatorio", {
                        body: text
                    });
                } catch(e) {}
                showToast("⏰ Recordatorio: " + text, "info");
                speakText("Recordatorio: " + text);
            }, timeMs);

            const mem = getAssistantMemory();
            mem.reminders = mem.reminders || [];
            mem.reminders.push({ text, dueAt: new Date(Date.now() + timeMs).toISOString() });
            saveAssistantMemory(mem);
        }

        function learnFromError(errorMsg, solution) {
            const mem = getAssistantMemory();
            mem.errorsSolved = mem.errorsSolved || [];
            mem.errorsSolved.push({
                error: errorMsg,
                solution: solution,
                timestamp: new Date().toISOString()
            });
            saveAssistantMemory(mem);
            showToast("🧠 Asistente: He aprendido a solucionar un nuevo error.", "success");
        }

