                                { label: 'Vector2', kind: monaco.languages.CompletionItemKind.Struct, insertText: 'Vector2($1, $2)$0', insertTextRules: monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet, detail: 'Vector 2D' },
                                { label: 'Color', kind: monaco.languages.CompletionItemKind.Struct, insertText: 'Color($1, $2, $3, $4)$0', insertTextRules: monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet, detail: 'Definición de color RGBA' }
