        function getModelsForCollaboration() {
            const activeModels = [];
            modelList.forEach(group => {
                let provId = '';
                if (group.group === 'Google AI') provId = 'google';
                else if (group.group === 'Anthropic') provId = 'anthropic';
                else if (group.group === 'OpenAI') provId = 'openai';
                else if (group.group === 'Groq') provId = 'groq';
                else if (group.group === 'Mistral') provId = 'mistral';
                else if (group.group === 'DeepSeek') provId = 'deepseek';
                else if (group.group === 'Moonshot (Kimi)') provId = 'moonshot';
                else if (group.group === 'xAI (Grok)') provId = 'xai';
                else if (group.group === 'OpenRouter') provId = 'openrouter';
                else if (group.group === 'Ollama (Local)') provId = 'ollama';
                
                // FIX: solo contar Ollama si está REALMENTE disponible (evita fijar el rol Coder
                // a un Ollama local inexistente y romper la colaboración para usuarios solo-nube).
                const isConfigured = provId === 'ollama'
                    ? (window.__ollamaAvailable === true)
                    : (apiKeysState[provId] && apiKeysState[provId].key);
                if (isConfigured) {
                    group.models.forEach(([id, name]) => {
                        activeModels.push(id);
                    });
                }
            });
            
            if (activeModels.length === 0) {
                throw new Error("No hay modelos de IA configurados. Configura al menos una clave de API.");
            }
            
            const strategy = document.getElementById('multi-agent-strategy').value;
            let planner = '';
            let coder = '';
            let reviewer = '';
            
            if (strategy === 'custom') {
                planner = document.getElementById('role-planner-select').value;
                coder = document.getElementById('role-coder-select').value;
                reviewer = document.getElementById('role-reviewer-select').value;
            } else if (strategy === 'performance') {
                planner = activeModels.find(m => m === 'claude-3-5-sonnet-latest') || 
                          activeModels.find(m => m === 'gpt-4o') || 
                          activeModels.find(m => m === 'gemini-2.5-pro') || 
                          activeModels[0];
                coder = activeModels.find(m => m === 'claude-3-5-sonnet-latest') || 
                        activeModels.find(m => m === 'gpt-4o') || 
                        activeModels[0];
                reviewer = activeModels.find(m => m === 'o3-mini') || 
                           activeModels.find(m => m === 'claude-3-5-sonnet-latest') || 
                           activeModels.find(m => m === 'gemini-2.5-pro') || 
                           activeModels[0];
            } else if (strategy === 'auto-hybrid') {
                // Planner: prefiere modelos de razonamiento (o3-mini, gemini-2.5-pro, gpt-4o, claude-3-5-sonnet)
                planner = activeModels.find(m => m === 'o3-mini') || 
                          activeModels.find(m => m === 'gemini-2.5-pro') || 
                          activeModels.find(m => m === 'gpt-4o') || 
                          activeModels.find(m => m === 'claude-3-5-sonnet-latest') || 
                          activeModels.find(m => m === 'deepseek-chat') ||
                          activeModels[0];
                // Coder: prefiere modelos de programación (claude-3-5-sonnet, deepseek-chat, gpt-4o, gemini-2.5-flash)
                coder = activeModels.find(m => m === 'claude-3-5-sonnet-latest') || 
                        activeModels.find(m => m === 'deepseek-chat') || 
                        activeModels.find(m => m === 'gpt-4o') || 
                        activeModels.find(m => m === 'gemini-2.5-flash') ||
                        activeModels[0];
                // Reviewer: prefiere modelos de revisión crítica o auditoría (o3-mini, gemini-2.5-pro, gpt-4o, claude-3-5-sonnet)
                reviewer = activeModels.find(m => m === 'gemini-2.5-pro') || 
                           activeModels.find(m => m === 'o3-mini') || 
                           activeModels.find(m => m === 'gpt-4o') || 
                           activeModels.find(m => m === 'claude-3-5-sonnet-latest') || 
                           activeModels[0];
            } else {
                planner = activeModels.find(m => m === 'gemini-2.5-flash') || 
                          activeModels.find(m => m === 'gemini-2.0-flash') ||
                          activeModels.find(m => m.startsWith('ollama/')) || 
                          activeModels[0];
                coder = activeModels.find(m => m.startsWith('ollama/qwen2.5-coder')) || 
                        activeModels.find(m => m === 'ollama/custom') ||
                        activeModels.find(m => m === 'gemini-2.5-flash') || 
                        activeModels[0];
                reviewer = activeModels.find(m => m === 'gemini-2.5-flash') || 
                           activeModels.find(m => m === 'gemini-2.0-flash') ||
                           activeModels.find(m => m.startsWith('ollama/')) || 
                           activeModels[0];
            }
            
            if (!planner) planner = activeModels[0];
            if (!coder) coder = activeModels[0];
            if (!reviewer) reviewer = activeModels[0];

            if (window.sessionOllamaRole === 'coder') {
                coder = window.sessionOllamaModel;
            } else if (window.sessionOllamaRole === 'reviewer') {
                reviewer = window.sessionOllamaModel;
            } else if (window.sessionOllamaRole === 'both') {
                coder = window.sessionOllamaModel;
                reviewer = window.sessionOllamaModel;
            }
            
            return { planner, coder, reviewer };
        }

        function getModelName(modelId) {
            if (modelId === 'ollama/custom') {
                const customModel = localStorage.getItem('nexus_ollama_custom_model') || 'qwen2.5-coder:7b';
                return `Ollama: ${customModel}`;
            }
            for (const group of modelList) {
                const found = group.models.find(m => m[0] === modelId);
                if (found) return found[1];
            }
            if (modelId.startsWith('ollama/')) {
                return modelId.replace('ollama/', 'Ollama: ');
            }
            return modelId;
        }

        function getStrategyName(strategyId) {
            if (strategyId === 'custom') return 'Personalizado (Roles)';
            if (strategyId === 'performance') return 'Alto Rendimiento';
            if (strategyId === 'auto-hybrid') return 'Multiproveedor Óptimo';
            return 'Economía de Tokens';
        }

        async function sendCollaborativeRequest(promptText, systemText, history = [], stepCallback, signal = null) {
            const { planner, coder, reviewer } = getModelsForCollaboration();
            const currentOS = (typeof process !== 'undefined') ? process.platform : 'win32';
            const operatingSystemName = currentOS === 'win32' ? 'Windows (win32, PowerShell)' : (currentOS === 'darwin' ? 'macOS (darwin, Bash)' : 'Linux (linux, Bash)');

            // Helper: ejecuta un paso del pipeline con retry automático ante fallo transitorio
            async function runStep(role, modelId, prompt, sysPrompt, label) {
                stepCallback(role, 'processing', label);
                try {
                    const result = await sendRequestToAI(modelId, prompt, sysPrompt, history, signal);
                    stepCallback(role, 'completed', result);
                    return { ok: true, text: result };
                } catch (err) {
                    // Si el error es de cancelación del usuario, propagar inmediatamente
                    if (err.name === 'AbortError' || (signal && signal.aborted)) {
                        stepCallback(role, 'error', 'Cancelado por el usuario.');
                        throw err;
                    }
                    // Para otros errores: marcar como advertencia y continuar con texto vacío
                    const msg = err.message || String(err);
                    console.warn(`[Multi-Agente] Agente "${role}" falló (${modelId}): ${msg}`);
                    stepCallback(role, 'error', `⚠️ ${msg} — el pipeline continúa con el output parcial.`);
                    return { ok: false, text: `[Error en ${role}: ${msg}]` };
                }
            }

            // Paso 1: Planificación
            const plannerSys = getPlannerSystemPrompt(operatingSystemName);
            const plannerRes = await runStep(
                'planner', planner, promptText, plannerSys,
                `Planificando con ${getModelName(planner)}...`
            );
            // Si el planificador falla por AbortError, la excepción ya se propagó arriba
            const plannerPlan = plannerRes.text;

            // Paso 2: Codificación
            const coderSys = getCoderSystemPrompt(operatingSystemName);
            const coderPrompt = `Solicitud original del usuario:\n${promptText}\n\nPlan de acción diseñado por el Planificador:\n${plannerPlan}`;
            const coderRes = await runStep(
                'coder', coder, coderPrompt, coderSys,
                `Codificando con ${getModelName(coder)}...`
            );
            const coderCode = coderRes.text;

            // Paso 3: Revisión
            const reviewerSys = getReviewerSystemPrompt(operatingSystemName);
            const reviewerPrompt = `Solicitud original del usuario:\n${promptText}\n\nPlan diseñado por el Planificador:\n${plannerPlan}\n\nCódigo y comandos propuestos por el Desarrollador:\n${coderCode}`;
            const reviewerRes = await runStep(
                'reviewer', reviewer, reviewerPrompt, reviewerSys,
                `Revisando con ${getModelName(reviewer)}...`
            );
            const reviewerResult = reviewerRes.text;

            // Informar si algún agente tuvo problemas
            const failedAgents = [plannerRes, coderRes, reviewerRes].filter(r => !r.ok).length;
            if (failedAgents > 0) {
                showToast(`Pipeline completado con ${failedAgents} agente(s) en error. Revisa el chat para ver detalles.`, 'warning');
            }

            return {
                planner:  { model: planner,  response: plannerPlan   },
                coder:    { model: coder,    response: coderCode     },
                reviewer: { model: reviewer, response: reviewerResult }
            };
        }

        async function generatePlannerPlan(promptText, history = [], signal = null) {
            const { planner } = getModelsForCollaboration();
            const currentOS = (typeof process !== 'undefined') ? process.platform : 'win32';
            const operatingSystemName = currentOS === 'win32' ? 'Windows (win32, PowerShell)' : (currentOS === 'darwin' ? 'macOS (darwin, Bash)' : 'Linux (linux, Bash)');
            const sysPrompt = getPlannerSystemPrompt(operatingSystemName);
            return await sendRequestToAI(planner, promptText, sysPrompt, history, signal);
        }

        async function runAgentCodeValidation(coderCode) {
            coderCode = normalizeAgentResponse(coderCode);
            const { exec } = require('child_process');

            // 1. Recolectar archivos a escribir y comandos a ejecutar (SIN tocar el disco aún).
            const writes = [];
            const writeFileRegex = /\[WRITE_FILE:\s*(.+?)\]([\s\S]*?)\[END_WRITE_FILE\]/g;
            let match;
            while ((match = writeFileRegex.exec(coderCode)) !== null) {
                let filePath = match[1].trim();
                if (!path.isAbsolute(filePath)) filePath = path.resolve(workspaceRoot, filePath);
                writes.push({ filePath, content: match[2] });
            }
            const runCommandRegex = /\[RUN_COMMAND\]([\s\S]*?)\[END_RUN_COMMAND\]/g;
            const commands = [];
            while ((match = runCommandRegex.exec(coderCode)) !== null) {
                commands.push(match[1].trim());
            }

            // SEGURIDAD: el Coder del equipo multi-agente debe respetar el ajuste de permisos
            // del agente. Si el usuario pide confirmación (por defecto), aprueba TODAS las
            // acciones (escrituras y comandos) antes de escribir en disco o ejecutar nada.
            const requirePermission = localStorage.getItem('nexus_agent_permissions') !== 'never';
            if (requirePermission && (writes.length || commands.length) && typeof showActionPermissionsModal === 'function') {
                const actions = [
                    ...writes.map(w => ({ type: 'write_file', label: 'Escribir archivo: ' + w.filePath, path: w.filePath })),
                    ...commands.map(c => ({ type: 'run_command', label: 'Ejecutar comando: ' + c, command: c }))
                ];
                const approved = await showActionPermissionsModal(actions);
                if (!approved || approved.length === 0) {
                    return { success: false, error: 'Acciones del agente denegadas por el usuario (permisos del agente).' };
                }
            }

            // 2. Escribir archivos.
            let filesWritten = false;
            for (const w of writes) {
                try {
                    const parent = path.dirname(w.filePath);
                    if (!fs.existsSync(parent)) fs.mkdirSync(parent, { recursive: true });
                    fs.writeFileSync(w.filePath, w.content, 'utf8');
                    filesWritten = true;
                    // Sincronizar contenido si está abierto en el editor
                    if (openFiles.includes(w.filePath)) {
                        const model = fileModels[w.filePath];
                        if (model) model.setValue(w.content);
                    }
                } catch (e) {
                    return { success: false, error: `Error al escribir el archivo '${path.basename(w.filePath)}': ${e.message}` };
                }
            }
            if (filesWritten) {
                renderExplorer();
            }

            // 3. Ejecutar comandos secuencialmente.
            if (commands.length === 0) {
                return { success: true };
            }

            for (const cmd of commands) {
                try {
                    const result = await new Promise((resolve) => {
                        exec(cmd, { cwd: workspaceRoot, timeout: 15000 }, (error, stdout, stderr) => {
                            if (error) {
                                resolve({
                                    success: false,
                                    error: `Comando fallido: "${cmd}"\nCódigo de salida: ${error.code || 'Desconocido'}\nStdout:\n${stdout}\nStderr:\n${stderr || error.message}`
                                });
                            } else {
                                resolve({ success: true, stdout, stderr });
                            }
                        });
                    });

                    if (!result.success) {
                        return result;
                    }
                } catch (err) {
                    return { success: false, error: `Error inesperado al ejecutar el comando "${cmd}": ${err.message}` };
                }
            }

            return { success: true };
        }

        async function executeCoderAndReviewer(promptText, plannerPlan, history = [], stepCallback, signal = null) {
            const { coder, reviewer } = getModelsForCollaboration();
            const currentOS = (typeof process !== 'undefined') ? process.platform : 'win32';
            const operatingSystemName = currentOS === 'win32' ? 'Windows (win32, PowerShell)' : (currentOS === 'darwin' ? 'macOS (darwin, Bash)' : 'Linux (linux, Bash)');
            
            // Paso 2: Codificación con Bucle de Auto-Corrección
            stepCallback('coder', 'processing', `Codificando con ${getModelName(coder)}...`);
            
            let coderCode = '';
            let attempts = 0;
            const maxAttempts = 3;
            let validationResult = { success: false, error: '' };
            let currentHistory = [...history];

            const sysPrompt = getCoderSystemPrompt(operatingSystemName);
            let coderPrompt = `Solicitud original del usuario:
${promptText}

Plan de acción diseñado por el Planificador:
${plannerPlan}`;

            while (attempts < maxAttempts) {
                attempts++;
                if (attempts > 1) {
                    stepCallback('coder', 'processing', `Error detectado. Auto-corrigiendo código (Intento ${attempts}/${maxAttempts})...`);
                }
                
                try {
                    coderCode = await sendRequestToAI(coder, coderPrompt, sysPrompt, currentHistory, signal);
                    coderCode = normalizeAgentResponse(coderCode);
                    
                    // Validar código y comandos (escribiendo y probando autónomamente)
                    validationResult = await runAgentCodeValidation(coderCode);
                    
                    if (validationResult.success) {
                        break; // Éxito en las pruebas
                    }
                    
                    // Si hay un error, actualizar prompt de reintento
                    coderPrompt = `Tu código o comandos anteriores fueron ejecutados pero fallaron con el siguiente error:
                    
[ERROR DE EJECUCIÓN]
${validationResult.error}

Por favor, analiza el error, identifica qué falló en los archivos creados o en los comandos ejecutados, y proporciona una versión corregida completa de todos los archivos y comandos en el mismo formato de tags.`;
                    
                } catch (err) {
                    if (attempts === maxAttempts) {
                        stepCallback('coder', 'error', err.message);
                        throw err;
                    }
                }
            }

            if (!validationResult.success) {
                stepCallback('coder', 'error', `Pruebas fallidas tras ${maxAttempts} intentos. Último error:\n${validationResult.error}`);
            } else {
                stepCallback('coder', 'completed', coderCode);
            }

            // Paso 3: Revisión
            stepCallback('reviewer', 'processing', `Revisando con ${getModelName(reviewer)}...`);
            let reviewerResult = '';
            try {
                const sysPromptReviewer = getReviewerSystemPrompt(operatingSystemName);
                const reviewerPrompt = `Solicitud original del usuario:
${promptText}

Plan diseñado por el Planificador:
${plannerPlan}

Código y comandos finales propuestos por el Desarrollador (Validados):
${coderCode}

${!validationResult.success ? `NOTA: La validación del código falló tras varios intentos con el siguiente error de consola:\n${validationResult.error}` : 'NOTA: El código se compiló/ejecutó con éxito en las pruebas automáticas.'}`;

                reviewerResult = await sendRequestToAI(reviewer, reviewerPrompt, sysPromptReviewer, currentHistory, signal);
                stepCallback('reviewer', 'completed', reviewerResult);
            } catch (err) {
                stepCallback('reviewer', 'error', err.message);
                throw err;
            }

            return {
                coder: { model: coder, response: coderCode },
                reviewer: { model: reviewer, response: reviewerResult }
            };
        }

        // NOTA: registros de proveedores + resolvers (getProviderForModel/getRealModelId/localUrlKey/localModelKey) movidos a modules/ai-providers.js


        function getApiKeyForModel(modelId) {
            const provider = getProviderForModel(modelId);
            if (!provider) return null;
            if (LOCAL_AI_PROVIDERS.has(provider)) {
                // Los servidores locales normalmente no requieren clave.
                if (!apiKeysState[provider]) return 'no-key-required';
                try {
                    return atob(apiKeysState[provider].key) || 'no-key-required';
                } catch(e) {
                    return 'no-key-required';
                }
            }
            if (!apiKeysState[provider]) return null;
            try {
                return atob(apiKeysState[provider].key);
            } catch (e) {
                return null;
            }
        }


        // ── Tool-calling nativo (function calling) para proveedores OpenAI-compat ──────
        // Esquema de herramientas del agente en formato OpenAI. Los tool_calls que
        // devuelva el modelo se convierten a las MISMAS etiquetas de texto que ya usa el
        // pipeline (toolCallsToTags), así el resto del flujo (loop de lectura, Cardinal,
        // ejecución con permisos) no cambia. Opt-in vía flag nexus_native_tools.
        const AGENT_TOOLS_SCHEMA = [
            { type: 'function', function: { name: 'write_file', description: 'Crea o sobrescribe un archivo con su contenido COMPLETO (sin resúmenes ni elipsis).', parameters: { type: 'object', properties: { path: { type: 'string', description: 'Ruta relativa o absoluta del archivo' }, content: { type: 'string', description: 'Contenido completo del archivo' } }, required: ['path', 'content'] } } },
            { type: 'function', function: { name: 'run_command', description: 'Ejecuta un comando en la terminal del sistema (PowerShell en Windows, Bash en Unix).', parameters: { type: 'object', properties: { command: { type: 'string' } }, required: ['command'] } } },
            { type: 'function', function: { name: 'read_file', description: 'Lee un archivo del workspace para ver su contenido.', parameters: { type: 'object', properties: { path: { type: 'string' } }, required: ['path'] } } },
            { type: 'function', function: { name: 'list_dir', description: 'Lista archivos y carpetas de un directorio del workspace (path vacío = raíz).', parameters: { type: 'object', properties: { path: { type: 'string' } }, required: [] } } },
            { type: 'function', function: { name: 'grep', description: 'Busca un patrón de texto/regex en todo el proyecto.', parameters: { type: 'object', properties: { pattern: { type: 'string' } }, required: ['pattern'] } } },
            { type: 'function', function: { name: 'run_3d_script', description: 'Ejecuta un script JavaScript compatible con Babylon.js en el motor 3D.', parameters: { type: 'object', properties: { code: { type: 'string' } }, required: ['code'] } } },
        ];
        // Delegado al núcleo agéntico testeable (modules/agent-core.js).
        function toolCallsToTags(toolCalls) { return AgentCore.toolCallsToTags(toolCalls); }
        function nativeToolsEnabled() { try { return localStorage.getItem('nexus_native_tools') === 'true'; } catch { return false; } }

        async function sendRequestToAI(modelId, promptText, systemText, history = [], signal = null, images = [], onToken = null) {
            const apiKey = getApiKeyForModel(modelId);
            if (!apiKey) {
                throw new Error(`No se ha configurado la API Key para el proveedor de este modelo. Haz clic en el engranaje ⚙ para configurarla.`);
            }

            const provider = getProviderForModel(modelId);
            const realModelId = getRealModelId(modelId, provider);
            let url = '';
            let options = {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                signal: signal
            };
            let sentTools = false; // ¿se envió el parámetro 'tools' en esta petición? (para fallback)

            // ── Streaming (SSE): opt-in (nexus_streaming). Emite deltas por onToken y
            // acumula el texto completo, que se devuelve para que el pipeline lo parsee.
            const streaming = (typeof onToken === 'function') && localStorage.getItem('nexus_streaming') === 'true';
            let __streamFull = '';
            if (streaming) {
                let sseBuf = '';
                options.onChunk = (chunk) => {
                    sseBuf += chunk;
                    const parsed = AgentCore.parseSSEDeltas(sseBuf, provider);
                    sseBuf = parsed.rest;
                    for (const d of parsed.deltas) { __streamFull += d; try { onToken(d); } catch (e) {} }
                };
            }
            
            // conversational memory is limited to the last 6 messages
            // Slice history to the last 5 messages, and combined with current prompt we get 6 total.
            const historyToUse = history.slice(-AGENT_HISTORY_WINDOW);
            
            if (provider === 'google') {
                url = `https://generativelanguage.googleapis.com/v1beta/models/${realModelId}:${streaming ? 'streamGenerateContent?alt=sse&' : 'generateContent?'}key=${apiKey}`;
                const contents = [];
                historyToUse.forEach(msg => {
                    contents.push({
                        role: msg.role === 'assistant' ? 'model' : 'user',
                        parts: [{ text: msg.content }]
                    });
                });
                
                const userParts = [{ text: promptText }];
                if (images && images.length > 0) {
                    images.forEach(img => {
                        userParts.push({
                            inlineData: {
                                mimeType: img.type,
                                data: img.base64
                            }
                        });
                    });
                }
                contents.push({
                    role: 'user',
                    parts: userParts
                });
                const payload = { contents };
                if (systemText) {
                    payload.systemInstruction = { parts: [{ text: systemText }] };
                }
                options.body = JSON.stringify(payload);
            } 
            else if (OPENAI_COMPAT_PROVIDERS.has(provider)) {
                if (LOCAL_AI_PROVIDERS.has(provider)) {
                    // Servidor local (Ollama, LM Studio, Jan, llama.cpp, vLLM): URL configurable.
                    let base = localStorage.getItem('nexus_' + provider + '_url') || LOCAL_AI_DEFAULT_URLS[provider];
                    base = base.replace('localhost', '127.0.0.1').replace(/\/$/, '');
                    url = base + '/v1/chat/completions';
                    if (apiKey && apiKey !== 'no-key-required' && apiKey !== 'local-active') {
                        options.headers['Authorization'] = `Bearer ${apiKey}`;
                    }
                } else {
                    // Proveedor en la nube compatible con OpenAI.
                    url = CLOUD_OPENAI_URLS[provider];
                    options.headers['Authorization'] = `Bearer ${apiKey}`;
                    if (provider === 'openrouter') {
                        options.headers['HTTP-Referer'] = 'https://github.com/nexus-ide';
                        options.headers['X-Title'] = 'Nexus IDE';
                    }
                }

                const messages = [];
                if (systemText) messages.push({ role: 'system', content: systemText });
                historyToUse.forEach(msg => {
                    messages.push({ role: msg.role, content: msg.content });
                });

                let userContent = promptText;
                if (images && images.length > 0) {
                    userContent = [{ type: 'text', text: promptText }];
                    images.forEach(img => {
                        userContent.push({
                            type: 'image_url',
                            image_url: {
                                url: `data:${img.type};base64,${img.base64}`
                            }
                        });
                    });
                }
                messages.push({ role: 'user', content: userContent });

                // Quita el prefijo "<provider>/" del id del modelo si lo lleva.
                let cleanModelId = realModelId;
                const prefix = provider + '/';
                if (cleanModelId.startsWith(prefix)) cleanModelId = cleanModelId.slice(prefix.length);
                if (LOCAL_AI_PROVIDERS.has(provider) && (cleanModelId === 'custom' || cleanModelId === '')) {
                    cleanModelId = localStorage.getItem(localModelKey(provider)) || LOCAL_AI_DEFAULT_MODELS[provider];
                }
                const openaiBody = { model: cleanModelId, messages: messages };
                if (streaming) openaiBody.stream = true;
                // Tool-calling nativo: solo para proveedores en la nube (los locales suelen
                // no soportarlo bien), si el usuario lo activó y NO estamos en streaming.
                if (nativeToolsEnabled() && !LOCAL_AI_PROVIDERS.has(provider) && !streaming) {
                    openaiBody.tools = AGENT_TOOLS_SCHEMA;
                    sentTools = true;
                }
                options.body = JSON.stringify(openaiBody);
            }
            else if (provider === 'anthropic') {
                url = 'https://api.anthropic.com/v1/messages';
                options.headers['x-api-key'] = apiKey;
                options.headers['anthropic-version'] = '2023-06-01';
                const messages = [];
                historyToUse.forEach(msg => {
                    messages.push({ role: msg.role, content: msg.content });
                });

                let userContent = promptText;
                if (images && images.length > 0) {
                    userContent = [{ type: 'text', text: promptText }];
                    images.forEach(img => {
                        userContent.push({
                            type: 'image',
                            source: {
                                type: 'base64',
                                media_type: img.type,
                                data: img.base64
                            }
                        });
                    });
                }
                messages.push({ role: 'user', content: userContent });
                options.body = JSON.stringify({
                    model: realModelId,
                    max_tokens: 4000,
                    system: systemText,
                    messages: messages,
                    ...(streaming ? { stream: true } : {})
                });
            }
            
            let response = await nodeHttpRequest(url, options);
            // Fallback: si enviamos 'tools' y el proveedor lo rechaza, reintentar sin ellos
            // (algunos endpoints OpenAI-compat no soportan function-calling).
            if (!response.ok && sentTools) {
                try {
                    const retryBody = JSON.parse(options.body);
                    delete retryBody.tools;
                    options.body = JSON.stringify(retryBody);
                    sentTools = false;
                    response = await nodeHttpRequest(url, options);
                } catch (e) { /* si el reintento tampoco va, cae al throw de abajo */ }
            }
            if (!response.ok) {
                const errText = await response.text();
                throw new Error(`API Error: ${response.status} - ${errText}`);
            }

            // Streaming: los deltas ya se emitieron por onToken durante la descarga;
            // devolvemos el texto acumulado para que el pipeline lo parsee igual.
            if (streaming) {
                return __streamFull;
            }

            const data = await response.json();
            if (provider === 'google') {
                return data.candidates[0].content.parts[0].text;
            } else if (OPENAI_COMPAT_PROVIDERS.has(provider)) {
                const msg = (data.choices && data.choices[0] && data.choices[0].message) || {};
                // Si el modelo usó function-calling, convertir los tool_calls a las
                // etiquetas de texto que ya entiende el pipeline; si no, devolver el texto.
                if (msg.tool_calls && msg.tool_calls.length) {
                    return (msg.content || '') + toolCallsToTags(msg.tool_calls);
                }
                return msg.content || '';
            } else if (provider === 'anthropic') {
                return data.content[0].text;
            }
        }

        // =========================================================================
        // PARSEADOR Y EJECUTOR DE ACCIONES DEL AGENTE
        // =========================================================================
        function formatMarkdown(text) {
            let parts = text.split(/(```[\s\S]*?```)/g);
            return parts.map(part => {
                if (part.startsWith('```')) {
                    const match = part.match(/```(\w*)\n([\s\S]*?)```/);
                    if (match) {
                        const lang = match[1] || 'plaintext';
                        const code = match[2].replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
                        return `
                            <div style="margin-block: 10px; border-radius: 6px; border: 1px solid #30363d; overflow: hidden;">
                                <div style="background: #161b22; padding: 6px 12px; font-family: monospace; font-size: 11px; color: #8b949e; border-bottom: 1px solid #30363d; display: flex; justify-content: space-between;">
                                    <span>${lang.toUpperCase()}</span>
                                    <span onclick="navigator.clipboard.writeText(this.parentElement.nextElementSibling.textContent); showToast('Copiado al portapapeles', 'success');" style="cursor: pointer; color: #8b949e;">Copiar</span>
                                </div>
                                <pre style="background: #0d1117; padding: 12px; margin: 0; overflow-x: auto; font-family: Consolas, monospace; font-size: 13px; color: #e6edf3;"><code>${code}</code></pre>
                            </div>`;
                    }
                    return part;
                } else {
                    let html = part
                        .replace(/&/g, '&amp;')
                        .replace(/</g, '&lt;')
                        .replace(/>/g, '&gt;')
                        .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
                        .replace(/`(.*?)`/g, '<code style="background:#272822; padding:2px 4px; border-radius:3px; font-family:monospace; color:#f92672;">$1</code>')
                        .replace(/^\*\s+(.*?)$/gm, '• $1')
                        .replace(/\n/g, '<br>');
                    return html;
                }
            }).join('');
        }

        function formatAgentActions(text) {
            let html = formatMarkdown(text);
            
            // Reemplazar visualmente el comando RUN_3D_SCRIPT
            html = html.replace(/\[RUN_3D_SCRIPT\]([\s\S]*?)\[END_RUN_3D_SCRIPT\]/g, (match, script) => {
                return `
                    <div style="background: #1d182b; border: 1px solid #7c3aed; padding: 10px; border-radius: 6px; margin-block: 8px; font-size: 13px; color: #a78bfa;">
                        🎮 <strong>Agente:</strong> Cargando script en el Motor 3D:
                        <pre style="background: #0d1117; padding: 8px; border-radius: 4px; color: #c9d1d9; font-size: 11px; margin-top: 5px; overflow-x: auto;"><code>${script.trim()}</code></pre>
                    </div>`;
            });

            // Reemplazar visualmente el comando WRITE_FILE
            html = html.replace(/\[WRITE_FILE:\s*(.+?)\]([\s\S]*?)\[END_WRITE_FILE\]/g, (match, filePath) => {
                return `
                    <div style="background: #1f2c1f; border: 1px solid #2ea44f; padding: 10px; border-radius: 6px; margin-block: 8px; font-size: 13px; color: #56d364;">
                        🟢 <strong>Agente:</strong> Archivo modificado/creado: <code style="background: #161b22; padding: 2px 4px; border-radius: 4px; color: #fff;">${filePath}</code>
                    </div>`;
            });
            
            // Reemplazar visualmente el comando RUN_COMMAND
            html = html.replace(/\[RUN_COMMAND\]([\s\S]*?)\[END_RUN_COMMAND\]/g, (match, command) => {
                return `
                    <div style="background: #2b2118; border: 1px solid #d29922; padding: 10px; border-radius: 6px; margin-block: 8px; font-size: 13px; color: #ecb22e;">
                        💻 <strong>Agente:</strong> Ejecutando en terminal: <code style="background: #161b22; padding: 2px 4px; border-radius: 4px; color: #fff;">${command.trim()}</code>
                    </div>`;
            });
            
            return html;
        }

        function escapeHtml(str) {
            return str
                .replace(/&/g, "&amp;")
                .replace(/</g, "&lt;")
                .replace(/>/g, "&gt;")
                .replace(/"/g, "&quot;")
                .replace(/'/g, "&#039;");
        }

        // Delegado al núcleo agéntico testeable (modules/agent-core.js).
        function normalizeAgentResponse(text) { return AgentCore.normalizeAgentResponse(text); }

        // Delegado al núcleo agéntico testeable (modules/agent-core.js).
        function parseAgentActions(text) { return AgentCore.parseAgentActions(text); }

        // ── Herramientas de LECTURA del agente (seguras: solo lectura, confinadas al
        // workspace). La lógica pura vive en modules/agent-core.js (testeable); aquí
        // sólo se le inyecta el workspaceRoot actual. ──
        function parseReadToolActions(text) { return AgentCore.parseReadToolActions(text); }
        function resolveInWorkspace(p) { return AgentCore.resolveInWorkspace(workspaceRoot, p); }
        function grepWorkspace(pattern) { return AgentCore.grepWorkspace(workspaceRoot, pattern); }

        // Ejecuta las lecturas solicitadas y devuelve un texto (redactado) para el modelo.
        // Delegado al núcleo agéntico testeable; le inyecta el workspaceRoot actual.
        function executeReadTools(actions) { return AgentCore.executeReadTools(workspaceRoot, actions); }

        function showActionPermissionsModal(actions) {
            return new Promise((resolve) => {
                // Notificación Nativa del Sistema
                try {
                    if (typeof Notification !== 'undefined') {
                        const showNotification = () => {
                            const notifText = actions.map(act => `• ${act.label}`).join('\n');
                            const notif = new Notification('🛡️ Nexus IDE: Solicitud de Permiso', {
                                body: `AIRI solicita realizar las siguientes acciones:\n${notifText}`,
                                requireInteraction: true
                            });
                            notif.onclick = () => {
                                if (typeof ipcRenderer !== 'undefined') {
                                    ipcRenderer.send('focus-window');
                                }
                            };
                        };
                        
                        if (Notification.permission === 'granted') {
                            showNotification();
                        } else if (Notification.permission !== 'denied') {
                            Notification.requestPermission().then(permission => {
                                if (permission === 'granted') {
                                    showNotification();
                                }
                            });
                        }
                    }
                } catch(e) {
                    console.error("Error al disparar notificación nativa:", e);
                }

                const backdrop = document.createElement('div');
                backdrop.id = 'nexus-agent-permission-backdrop';
                backdrop.style.cssText = `
                    position: fixed; top: 0; left: 0; width: 100vw; height: 100vh;
                    background: rgba(0, 0, 0, 0.75); backdrop-filter: blur(5px);
                    display: flex; justify-content: center; align-items: center;
                    z-index: 10000; font-family: 'Segoe UI', system-ui, sans-serif;
                `;
                
                const modal = document.createElement('div');
                modal.style.cssText = `
                    width: 600px; max-width: 90%; max-height: 80vh; background: #161b22;
                    border: 1px solid #30363d; border-radius: 12px;
                    box-shadow: 0 24px 64px rgba(0,0,0,0.8); display: flex;
                    flex-direction: column; overflow: hidden; animation: winOpen 0.15s ease;
                `;
                
                let actionItemsHtml = '';
                actions.forEach((act, idx) => {
                    let typeIcon = '📝';
                    let contentToShow = '';
                    if (act.type === '3d_script') {
                        typeIcon = '🎮';
                        contentToShow = act.content;
                    } else if (act.type === 'write_file') {
                        typeIcon = '📄';
                        contentToShow = act.content;
                    } else if (act.type === 'run_command') {
                        typeIcon = '💻';
                        contentToShow = act.command;
                    }
                    
                    actionItemsHtml += `
                        <div style="padding: 12px; border-bottom: 1px solid #21262d; display: flex; flex-direction: column; gap: 6px;">
                            <div style="display: flex; align-items: center; justify-content: space-between; gap: 10px;">
                                <div style="display: flex; align-items: center; gap: 10px; flex: 1; min-width: 0;">
                                    <input type="checkbox" id="perm-check-${idx}" checked style="cursor: pointer; width: 16px; height: 16px; accent-color: #7c3aed; flex-shrink: 0;">
                                    <span style="font-size: 13px; font-weight: 500; color: #e6edf3; font-family: 'JetBrains Mono', Consolas, monospace; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">
                                        ${typeIcon} ${act.label}
                                    </span>
                                </div>
                                <button onclick="window.togglePermContent(${idx})" style="background: #21262d; border: 1px solid #30363d; border-radius: 4px; color: #8b949e; font-size: 10px; padding: 3px 8px; cursor: pointer; transition: all 0.2s; white-space: nowrap; display:inline-flex; align-items:center; gap:4px;"><svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg> Ver Detalle</button>
                            </div>
                            <pre style="margin: 4px 0 0 26px; padding: 8px; background: #0d1117; border: 1px solid #30363d; border-radius: 6px; font-size: 11px; color: #c9d1d9; overflow-x: auto; max-height: 180px; white-space: pre-wrap; word-break: break-all; display: none; font-family: 'JetBrains Mono', Consolas, monospace; line-height: 1.4;" id="perm-content-${idx}">${escapeHtml(contentToShow)}</pre>
                        </div>
                    `;
                });
                
                modal.innerHTML = `
                    <div style="padding: 18px 24px; background: #0d1117; border-bottom: 1px solid #30363d; display: flex; align-items: center; justify-content: space-between;">
                        <div style="font-weight: 700; font-size: 15px; color: #ffb454; display: flex; align-items: center; gap: 8px;">
                            🛡️ Seguridad del Agente: Confirmación de Acciones
                        </div>
                    </div>
                    <div style="padding: 14px 24px; font-size: 12px; color: #8b949e; background: #161b22; border-bottom: 1px solid #30363d; line-height: 1.5;">
                        El Agente de Inteligencia Artificial está solicitando realizar cambios en tu espacio de trabajo. Revisa y selecciona qué acciones deseas autorizar:
                    </div>
                    <div style="flex: 1; overflow-y: auto; background: #0d1117; max-height: 40vh;">
                        ${actionItemsHtml}
                    </div>
                    <div style="padding: 16px 24px; background: #0d1117; border-top: 1px solid #30363d; display: flex; gap: 12px; justify-content: flex-end;">
                        <button id="perm-btn-reject" class="dash-btn" style="padding: 8px 16px; font-size: 12px; border-color: #f85149; color: #f85149; background: transparent;">✕ Denegar Todo</button>
                        <button id="perm-btn-approve" class="dash-btn dash-primary-btn" style="padding: 8px 16px; font-size: 12px; background: #3fb950; border-color: #3fb950; color: #fff;">✓ Autorizar Seleccionadas</button>
                    </div>
                `;
                
                backdrop.appendChild(modal);
                document.body.appendChild(backdrop);
                
                // Mostrar notificación visual en AIRI
                if (typeof window.showAiriNotification === 'function') {
                    window.showAiriNotification(
                        "He solicitado algunos permisos para realizar cambios. ¿Los apruebas?",
                        "permission",
                        () => {
                            backdrop.remove();
                            window.activePermissionPromise = null;
                            resolve(actions);
                        },
                        () => {
                            backdrop.remove();
                            window.activePermissionPromise = null;
                            resolve([]);
                        }
                    );
                }

                // Guardar referencia global del resolutor para control remoto (Telegram)
                window.activePermissionPromise = {
                    resolve: (approved) => {
                        backdrop.remove();
                        window.hideAiriNotification();
                        window.activePermissionPromise = null;
                        resolve(approved);
                    },
                    actions: actions
                };

                // Enviar notificación a Telegram y/o Discord si están configurados
                if (typeof ipcRenderer !== 'undefined') {
                    const actionListStr = actions.map((act, i) => `${i+1}. ${act.label}`).join('\n');
                    const notifMsg = `⚠️ *AIRI solicita permisos en tu PC*:\n${actionListStr}\n\nResponde \`/approve\` para autorizar todo o \`/deny\` para rechazar.`;
                    ipcRenderer.send('send-telegram-notification', notifMsg);
                    if (window.NexusDiscord) window.NexusDiscord.notify(notifMsg);
                }
                
                window.togglePermContent = (idx) => {
                    const box = document.getElementById(`perm-content-${idx}`);
                    if (box) {
                        box.style.display = box.style.display === 'none' ? 'block' : 'none';
                    }
                };
                
                document.getElementById('perm-btn-reject').addEventListener('click', () => {
                    backdrop.remove();
                    window.hideAiriNotification();
                    window.activePermissionPromise = null;
                    resolve([]);
                });
                
                document.getElementById('perm-btn-approve').addEventListener('click', () => {
                    const approved = [];
                    actions.forEach((act, idx) => {
                        const chk = document.getElementById(`perm-check-${idx}`);
                        if (chk && chk.checked) {
                            approved.push(act);
                        }
                    });
                    backdrop.remove();
                    window.hideAiriNotification();
                    window.activePermissionPromise = null;
                    resolve(approved);
                });
            });
        }

        // Ejecuta un comando CAPTURANDO su salida (para que el agente pueda OBSERVAR el
        // resultado en el bucle ReAct). Se muestra también en el terminal integrado. Con
        // timeout de 120 s para no colgarse con procesos interactivos/servidores.
        // Delegado al núcleo agéntico testeable; le inyecta el cwd, el hook del terminal
        // y (si el usuario activó el sandbox y Docker está disponible) la config de Docker
        // para ejecutar el comando aislado en un contenedor.
        let __sandboxDockerAvail = null; // cache: null=desconocido, true/false
        async function runCommandCaptured(command) {
            let sandbox = null;
            if (localStorage.getItem('nexus_sandbox') === 'docker') {
                if (__sandboxDockerAvail === null) {
                    __sandboxDockerAvail = await AgentCore.checkDockerAvailable();
                    if (!__sandboxDockerAvail) showToast('⚠️ Sandbox activado pero Docker no está disponible; los comandos se ejecutan en el host.', 'warning');
                }
                if (__sandboxDockerAvail) {
                    sandbox = { image: localStorage.getItem('nexus_sandbox_image') || 'node:20-slim', workspace: workspaceRoot };
                }
            }
            return AgentCore.runCommandCaptured(command, {
                cwd: workspaceRoot,
                onOutput: (typeof appendTerminalOutput === 'function') ? appendTerminalOutput : null,
                sandbox
            });
        }

        async function executeAgentCommands(text) {
            text = normalizeAgentResponse(text);
            const actions = parseAgentActions(text);
            if (actions.length === 0) return { executed: false, summary: '' };

            const requirePermission = localStorage.getItem('nexus_agent_permissions') !== 'never';
            let approvedActions = [];

            if (requirePermission) {
                approvedActions = await showActionPermissionsModal(actions);
            } else {
                approvedActions = actions;
            }

            if (approvedActions.length === 0) {
                showToast("Acciones del agente canceladas o denegadas por el usuario", "info");
                return { executed: false, summary: '' };
            }

            let executed = false;
            const results = []; // resumen de resultados para el bucle ReAct

            for (const action of approvedActions) {
                if (action.type === '3d_script') {
                    const code = action.content;
                    const filePath = path.resolve(workspaceRoot, 'script_juego.js');
                    try {
                        fs.writeFileSync(filePath, code, 'utf8');
                        showToast("Script del juego guardado en script_juego.js", 'success');
                        
                        if (openFiles.includes(filePath)) {
                            const model = fileModels[filePath];
                            if (model) model.setValue(code);
                        } else {
                            openFileInEditor(filePath);
                        }
                    } catch(e) {
                        console.error("Error al escribir script_juego.js:", e);
                    }
                    
                    openMotor3DWindow();
                    
                    if (babylonScene) {
                        try {
                            babylonCustomScript = new Function("mesh", "scene", "BABYLON", code);
                            is3DPlaying = true;
                            showToast("Script del juego cargado en el Motor 3D", "success");
                        } catch(e) {
                            showToast("Error de Sintaxis en Script: " + e.message, "error");
                        }
                    } else {
                        window.pending3DScript = code;
                    }
                    executed = true;
                } else if (action.type === 'write_file') {
                    let filePath = action.path;
                    const content = action.content;
                    
                    if (!path.isAbsolute(filePath)) {
                        filePath = path.resolve(workspaceRoot, filePath);
                    }
                    
                    try {
                        const parent = path.dirname(filePath);
                        if (!fs.existsSync(parent)) {
                            fs.mkdirSync(parent, { recursive: true });
                        }
                        fs.writeFileSync(filePath, content, 'utf8');
                        showToast(`Archivo escrito: ${path.basename(filePath)}`, 'success');

                        if (openFiles.includes(filePath)) {
                            const model = fileModels[filePath];
                            if (model) model.setValue(content);
                        }
                        results.push(`✅ Escrito ${path.basename(filePath)} (${(content.match(/\n/g) || []).length + 1} líneas)`);
                        executed = true;
                    } catch (e) {
                        showToast(`Error al escribir archivo: ${e.message}`, 'error');
                        results.push(`❌ Error escribiendo ${filePath}: ${e.message}`);
                    }
                } else if (action.type === 'run_command') {
                    showToast(`Agente ejecutando: ${action.command}`, 'info');
                    const cap = await runCommandCaptured(action.command);
                    results.push(`$ ${action.command}\n${cap.output}`);
                    executed = true;
                } else if (action.type === 'run_skill') {
                    showToast("Agente ejecutando Habilidad: " + action.skillId, "info");
                    
                    const skillId = action.skillId;
                    const args = action.args;
                    const skills = window.getSkills();
                    const skill = skills.find(s => s.id === skillId);
                    
                    if (!skill) {
                        showToast("Habilidad '" + skillId + "' no encontrada", "error");
                        continue;
                    }
                    
                    let commandToRun = skill.commandTemplate || '';
                    if (commandToRun) {
                        commandToRun = commandToRun.replace(/{args}/g, args);
                        sendTerminalCommand(commandToRun);
                        executed = true;
                    } else if (skill.scriptCode) {
                        const isNode = skill.scriptCode.includes('require(') || skill.scriptCode.includes('const ') || skill.scriptCode.includes('let ');
                        const ext = isNode ? '.js' : '.py';
                        const runner = isNode ? 'node' : 'python';
                        const scriptPath = path.join(workspaceRoot, 'skills', skillId + ext);
                        
                        try {
                            const parent = path.dirname(scriptPath);
                            if (!fs.existsSync(parent)) fs.mkdirSync(parent, { recursive: true });
                            fs.writeFileSync(scriptPath, skill.scriptCode, 'utf8');
                            
                            const fullCmd = runner + ' "' + scriptPath + '" ' + args;
                            showToast("Ejecutando script de habilidad: " + fullCmd, "info");
                            sendTerminalCommand(fullCmd);
                            executed = true;
                        } catch(e) {
                            showToast("Error al guardar/ejecutar script: " + e.message, "error");
                        }
                    } else {
                        showToast("La habilidad '" + skillId + "' no tiene comando ni script configurado", "warning");
                    }
                }
            }

            if (executed) {
                renderExplorer();
                if (typeof window.showAiriNotification === 'function') {
                    window.showAiriNotification("¡He completado la tarea de forma exitosa!", "success");
                }
                if (typeof ipcRenderer !== 'undefined') {
                    const doneMsg = "✅ *AIRI*: ¡He terminado las tareas en el PC exitosamente!";
                    ipcRenderer.send('send-telegram-notification', doneMsg);
                    if (window.NexusDiscord) window.NexusDiscord.notify(doneMsg);
                }
            }
            return { executed, summary: redactSecrets(results.join('\n\n')) };
        }

        // =========================================================================
        // PANEL DE ASISTENTE IA & RAG LOCAL IN-MEMORY
        // =========================================================================
        window.localRagDatabase = { filesCount: 0, chunksCount: 0, chunks: [] };

        window.showAiAssistantModal = function() {
            const screen = document.getElementById('nexus-ai-assistant-screen');
            if (screen) {
                screen.style.display = 'flex';
                screen.offsetHeight; // trigger reflow
                screen.style.opacity = '1';
                if (typeof window.renderAgentsList === 'function') {
                    window.renderAgentsList();
                }
            }
        };

        window.closeAiAssistantModal = function() {
            const screen = document.getElementById('nexus-ai-assistant-screen');
            if (screen) {
                screen.style.opacity = '0';
                setTimeout(() => {
                    if (screen.style.opacity === '0') {
                        screen.style.display = 'none';
                    }
                }, 300);
            }
        };

        window.renderAgentsList = function() {
            const container = document.getElementById('ai-agents-list-container');
            if (!container) return;
            container.innerHTML = '';

            const activeModelList = [];
            modelList.forEach(group => {
                let provId = '';
                if (group.group === 'Google AI') provId = 'google';
                else if (group.group === 'Anthropic') provId = 'anthropic';
                else if (group.group === 'OpenAI') provId = 'openai';
                else if (group.group === 'Groq') provId = 'groq';
                else if (group.group === 'Mistral') provId = 'mistral';
                else if (group.group === 'DeepSeek') provId = 'deepseek';
                else if (group.group === 'Moonshot (Kimi)') provId = 'moonshot';
                else if (group.group === 'xAI (Grok)') provId = 'xai';
                else if (group.group === 'OpenRouter') provId = 'openrouter';
                else if (group.group === 'Ollama (Local)') provId = 'ollama';
                
                const isConfigured = provId === 'ollama' || (apiKeysState[provId] && apiKeysState[provId].key);
                if (isConfigured) {
                    group.models.forEach(([id, name]) => {
                        activeModelList.push({ id, name });
                    });
                }
            });

            // Get standard agents
            const agents = [
                {
                    id: 'planner',
                    name: 'Planificador de Tareas',
                    role: 'planner',
                    emoji: '🧠',
                    desc: 'Analiza la solicitud del usuario, diseña un plan paso a paso y define los objetivos.',
                    key: 'nexus_multi_agent_role_planner',
                    promptKey: 'nexus_multi_agent_role_planner_prompt',
                    defaultPrompt: (typeof NexusLocalization !== 'undefined' ? NexusLocalization.t('planner_system_prompt') : '')
                },
                {
                    id: 'coder',
                    name: 'Desarrollador Principal',
                    role: 'coder',
                    emoji: '✍️',
                    desc: 'Escribe el código, crea archivos y propone los comandos de ejecución.',
                    key: 'nexus_multi_agent_role_coder',
                    promptKey: 'nexus_multi_agent_role_coder_prompt',
                    defaultPrompt: (typeof NexusLocalization !== 'undefined' ? NexusLocalization.t('coder_system_prompt') : '')
                },
                {
                    id: 'reviewer',
                    name: 'Auditor de Código',
                    role: 'reviewer',
                    emoji: '🔍',
                    desc: 'Audita las propuestas del Desarrollador, busca bugs y ejecuta el linter.',
                    key: 'nexus_multi_agent_role_reviewer',
                    promptKey: 'nexus_multi_agent_role_reviewer_prompt',
                    defaultPrompt: (typeof NexusLocalization !== 'undefined' ? NexusLocalization.t('reviewer_system_prompt') : '')
                }
            ];

            // Render each agent card
            agents.forEach(agent => {
                const card = document.createElement('div');
                card.style.cssText = 'background: rgba(255,255,255,0.02); border: 1px solid rgba(255,255,255,0.06); padding: 16px; border-radius: 12px; display: flex; flex-direction: column; gap: 12px;';
                
                const currentModel = localStorage.getItem(agent.key) || (activeModelList.length > 0 ? activeModelList[0].id : '');
                
                let modelSelectHtml = `<select onchange="localStorage.setItem('${agent.key}', this.value); if (typeof updateMultiAgentUI === 'function') updateMultiAgentUI();" style="background:#161b22; color:#fff; border:1px solid #30363d; border-radius:6px; padding:6px; font-size:12px; width:200px; outline:none; cursor:pointer;">`;
                if (activeModelList.length === 0) {
                    modelSelectHtml += `<option value="">Ningún modelo configurado</option>`;
                } else {
                    activeModelList.forEach(m => {
                        const selected = m.id === currentModel ? 'selected' : '';
                        modelSelectHtml += `<option value="${m.id}" ${selected}>${m.name}</option>`;
                    });
                }
                modelSelectHtml += `</select>`;

                const promptVal = localStorage.getItem(agent.promptKey) || agent.defaultPrompt || '';

                card.innerHTML = `
                    <div style="display:flex; justify-content:space-between; align-items:flex-start; flex-wrap:wrap; gap:12px;">
                        <div style="display:flex; align-items:center; gap:12px;">
                            <span style="font-size:24px;">${agent.emoji}</span>
                            <div>
                                <div style="font-weight:600; font-size:14px; color:#fff;">${agent.name}</div>
                                <div style="font-size:11px; color:#8b949e; margin-top:2px;">${agent.desc}</div>
                            </div>
                        </div>
                        <div style="display:flex; align-items:center; gap:10px;">
                            <span style="font-size:11px; color:#8b949e;">Modelo:</span>
                            ${modelSelectHtml}
                        </div>
                    </div>
                    
                    <div style="display:flex; flex-direction:column; gap:6px; background:rgba(0,0,0,0.15); border:1px solid rgba(255,255,255,0.03); border-radius:8px; padding:10px;">
                        <div style="display:flex; justify-content:space-between; align-items:center;">
                            <span style="font-size:11px; color:#8b949e; font-weight:600; text-transform:uppercase; font-family: inherit;">Instrucciones del Sistema (System Prompt)</span>
                            <button onclick="window.editAgentPrompt('${agent.id}', '${agent.promptKey}', '${agent.name}')" style="background:none; border:none; color:#a78bfa; font-size:11px; cursor:pointer; display:flex; align-items:center; gap:4px; font-family: inherit;">✏️ Editar Prompt</button>
                        </div>
                        <pre style="margin:4px 0 0 0; white-space:pre-wrap; font-family:monospace; font-size:11px; color:#c9d1d9; max-height:80px; overflow-y:auto; line-height:1.4;">${escapeHtml(promptVal)}</pre>
                    </div>
                `;
                container.appendChild(card);
            });
        };

        window.editAgentPrompt = function(agentId, promptKey, agentName) {
            const defaultPrompt = (typeof NexusLocalization !== 'undefined' ? (agentId === 'planner' ? NexusLocalization.t('planner_system_prompt') : (agentId === 'coder' ? NexusLocalization.t('coder_system_prompt') : NexusLocalization.t('reviewer_system_prompt'))) : '');
            const currentVal = localStorage.getItem(promptKey) || defaultPrompt;
            
            const modalId = 'agent-prompt-modal-' + Date.now();
            const modal = document.createElement('div');
            modal.id = modalId;
            modal.style.cssText = `
                position: fixed;
                top: 0;
                left: 0;
                width: 100vw;
                height: 100vh;
                background: rgba(0, 0, 0, 0.7);
                display: flex;
                align-items: center;
                justify-content: center;
                z-index: 10000;
                backdrop-filter: blur(10px);
                font-family: inherit;
            `;
            
            modal.innerHTML = `
                <div style="background: #0d1117; border: 1px solid #30363d; border-radius: 12px; width: 600px; max-width: 90%; max-height: 80vh; display: flex; flex-direction: column; box-shadow: 0 8px 32px rgba(0,0,0,0.5); overflow: hidden;">
                    <div style="padding: 16px; border-bottom: 1px solid #30363d; display: flex; justify-content: space-between; align-items: center; background: #161b22;">
                        <span style="font-weight: bold; color: #fff; font-size: 14px;">Editar Prompt: ${agentName}</span>
                        <button onclick="document.getElementById('${modalId}').remove()" style="background: none; border: none; color: #8b949e; cursor: pointer; font-size: 16px;">&times;</button>
                    </div>
                    <div style="padding: 16px; display: flex; flex-direction: column; gap: 10px; overflow-y: auto; flex: 1;">
                        <label style="font-size: 12px; color: #8b949e;">Instrucciones específicas para este agente:</label>
                        <textarea id="${modalId}-textarea" style="flex:1; min-height: 250px; background: #0d1117; border: 1px solid #30363d; border-radius: 6px; padding: 10px; color: #c9d1d9; font-family: monospace; font-size: 12px; line-height: 1.5; resize: vertical; outline: none;">${currentVal}</textarea>
                        <p style="margin:0; font-size:11px; color:#8b949e; line-height:1.4;">
                            * Puedes utilizar variables dinámicas como <code>{workspaceRoot}</code>, <code>{activeFilePath}</code> y <code>{openFiles}</code>, las cuales se reemplazarán con sus valores correspondientes antes de enviar la petición a la IA.
                        </p>
                    </div>
                    <div style="padding: 12px 16px; border-top: 1px solid #30363d; display: flex; justify-content: flex-end; gap: 10px; background: #161b22;">
                        <button id="${modalId}-reset" style="background: transparent; border: 1px solid #ff7b72; color: #ff7b72; border-radius: 6px; padding: 6px 12px; font-size: 12px; cursor: pointer;">Restablecer</button>
                        <button onclick="document.getElementById('${modalId}').remove()" class="dash-btn" style="padding: 6px 12px;">Cancelar</button>
                        <button id="${modalId}-save" class="dash-btn dash-primary-btn" style="padding: 6px 12px; background: #7c3aed; color: #fff; border: none; border-radius: 6px; cursor: pointer; font-weight: 500;">Guardar Cambios</button>
                    </div>
                </div>
            `;
            
            document.body.appendChild(modal);
            
            document.getElementById(`${modalId}-reset`).addEventListener('click', () => {
                localStorage.removeItem(promptKey);
                modal.remove();
                window.renderAgentsList();
                showToast('Prompt restablecido a valores por defecto', 'info');
            });
            
            document.getElementById(`${modalId}-save`).addEventListener('click', () => {
                const newVal = document.getElementById(`${modalId}-textarea`).value;
                localStorage.setItem(promptKey, newVal);
                modal.remove();
                window.renderAgentsList();
                showToast("Prompt guardado correctamente", "success");
            });
        };

        window.showCreateAgentPrompt = function() {
            showToast("Creación de agentes personalizados en desarrollo. Edite los agentes del pipeline principal abajo.", "info");
        };

        window.switchAiTab = function(tabName) {
            const tabs = ['agents', 'remote', 'rag', 'airi'];
            tabs.forEach(t => {
                const el = document.getElementById(`aiTabContent-${t}`);
                if (el) el.style.display = 'none';
                
                const btn = document.getElementById(`tabBtn-${t}`);
                if (btn) {
                    btn.classList.remove('active');
                    btn.style.color = '#8b949e';
                    btn.style.borderBottom = '2px solid transparent';
                }
            });
            
            const activeContent = document.getElementById(`aiTabContent-${tabName}`);
            if (activeContent) {
                if (tabName === 'remote') activeContent.style.display = 'block';
                else activeContent.style.display = 'flex';
            }
            const activeBtn = document.getElementById(`tabBtn-${tabName}`);
            if (activeBtn) {
                activeBtn.classList.add('active');
                activeBtn.style.color = '#fff';
                activeBtn.style.borderBottom = '2px solid #7c3aed';
            }
        };

        window.populateBrowserVoices = function() {
            if (typeof window.speechSynthesis === 'undefined') return;
            const select = document.getElementById('airi-browser-voice');
            if (!select) return;
            
            const voices = window.speechSynthesis.getVoices();
            select.innerHTML = '';
            
            voices.forEach(voice => {
                const option = document.createElement('option');
                option.value = voice.voiceURI;
                option.textContent = `${voice.name} (${voice.lang})`;
                select.appendChild(option);
            });
            
            const savedVoice = localStorage.getItem('airi_browser_voice');
            if (savedVoice) {
                select.value = savedVoice;
            } else if (voices.length > 0) {
                localStorage.setItem('airi_browser_voice', voices[0].voiceURI);
                select.value = voices[0].voiceURI;
            }
        };

        window.toggleAiriVoice = function(enabled, speakFeedback = true) {
            localStorage.setItem('airi_voice_enabled', enabled ? 'true' : 'false');
            
            const checkbox = document.getElementById('airi-voice-enabled');
            if (checkbox) checkbox.checked = enabled;
            
            const bg = document.getElementById('airi-voice-toggle-bg');
            const dot = document.getElementById('airi-voice-toggle-dot');
            if (bg && dot) {
                if (enabled) {
                    bg.style.backgroundColor = '#7c3aed';
                    dot.style.transform = 'translateX(16px)';
                } else {
                    bg.style.backgroundColor = '#30363d';
                    dot.style.transform = 'translateX(0px)';
                }
            }
            
            if (enabled && speakFeedback) {
                const msg = NexusLocalization.currentLanguage === 'es' ? 
                    "¡Voz habilitada! Hola, soy AIRI." : 
                    "Voice enabled! Hello, I am AIRI.";
                setTimeout(() => { window.speakAiri(msg); }, 100);
            } else if (!enabled) {
                if (typeof window.speechSynthesis !== 'undefined') {
                    window.speechSynthesis.cancel();
                }
                if (window.airiAudioPlayer) {
                    window.airiAudioPlayer.pause();
                    window.airiAudioPlayer = null;
                }
            }
        };

