            function cargarModelo3DLocal(filePath) {
                if (!babylonScene) {
                    showToast("Primero inicia el Motor 3D", "warning");
                    return;
                }
                try {
                    const fs = require('fs');
                    const path = require('path');
                    if (!fs.existsSync(filePath)) {
                        showToast("No se encontró el archivo del modelo 3D", "error");
                        return;
                    }
                    showToast(`Cargando modelo generado...`, "info");
                    const data = fs.readFileSync(filePath);
                    const blob = new Blob([data], { type: 'application/octet-stream' });
                    const blobUrl = URL.createObjectURL(blob);
                    const filename = path.basename(filePath);
                    const extension = "." + filename.split('.').pop().toLowerCase();

                    BABYLON.SceneLoader.ImportMesh("", "", blobUrl, babylonScene, function (meshes) {
                        if (meshes.length > 0) {
                            babylonScene.meshes.slice().forEach(m => {
                                if (m.name !== 'ground' && !meshes.includes(m)) {
                                    m.dispose();
                                }
                            });

                            babylonActiveMesh = meshes[0];
                            
                            let minVal = new BABYLON.Vector3(Number.MAX_VALUE, Number.MAX_VALUE, Number.MAX_VALUE);
                            let maxVal = new BABYLON.Vector3(-Number.MAX_VALUE, -Number.MAX_VALUE, -Number.MAX_VALUE);
                            
                            meshes.forEach(m => {
                                const boundingInfo = m.getBoundingInfo();
                                const subMin = boundingInfo.boundingBox.minimumWorld;
                                const subMax = boundingInfo.boundingBox.maximumWorld;
                                minVal = BABYLON.Vector3.Minimize(minVal, subMin);
                                maxVal = BABYLON.Vector3.Maximize(maxVal, subMax);
                            });
                            
                            const size = maxVal.subtract(minVal);
                            const maxDimension = Math.max(size.x, size.y, size.z);
                            const scaleFactor = 2.0 / maxDimension;
                            
                            meshes.forEach(m => {
                                if (!m.parent) {
                                    m.scaling = new BABYLON.Vector3(scaleFactor, scaleFactor, scaleFactor);
                                    m.position = new BABYLON.Vector3(0, 0.75, 0);
                                }
                            });
                            
                            if (!babylonScene.lights.length) {
                                new BABYLON.HemisphericLight("light", new BABYLON.Vector3(0, 1, 0), babylonScene);
                            }
                            
                            if (typeof refreshInspector === 'function') refreshInspector();
                            showToast("¡Modelo cargado con éxito!", "success");
                        }
                    }, null, null, extension);
                } catch(err) {
                    showToast("Error al cargar modelo local: " + err.message, "error");
                }
            }
            window.cargarModelo3DLocal = cargarModelo3DLocal;

