                                "11": { "inputs": { "images": ["8", 0], "fps": 16, "filename_prefix": "nexus_ltx", "format": "video/h264-mp4", "save_output": true, "frame_rate": 16, "pingpong": false, "loop_count": 0 }, "class_type": "VHS_VideoCombine" }
